import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface CatecheticalPlan {
  tema: string;
  leitura_biblica: string;
  dinamica: string;
  oracao: string;
  atividade: string;
}

export const generateCatecheticalPlan = async (
  etapa: string,
  tempoLiturgico: string,
  userPrompt: string
): Promise<string> => {
  try {
    const systemInstruction = `
      Você é um coordenador de catequese e teólogo católico experiente, fiel ao Magistério da Igreja Católica.
      Sua missão é ajudar catequistas a preparar encontros.
      Sempre use uma linguagem pastoral, acolhedora e institucional.
      A resposta deve ser estruturada, clara e prática.
      Se o usuário pedir algo fora do contexto da fé católica ou moralmente inadequado, corrija gentilmente e traga para a perspectiva da Igreja.

      Estrutura sugerida para a resposta (use Markdown):
      ## Tema do Encontro
      **Leitura Bíblica:** [Citação]
      **Objetivo:** [Breve explicação]

      ### 1. Acolhida e Oração Inicial
      [Sugestão]

      ### 2. Desenvolvimento do Tema
      [Pontos principais para o catequista abordar]

      ### 3. Dinâmica ou Atividade Prática
      [Descrição passo a passo]

      ### 4. Oração Final e Compromisso
      [Sugestão de oração e gesto concreto]
    `;

    const fullPrompt = `
      Contexto: Turma de ${etapa}.
      Tempo Litúrgico: ${tempoLiturgico}.
      Solicitação do Catequista: ${userPrompt}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: fullPrompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7, // Balanced creativity and adherence
      }
    });

    return response.text || "Não foi possível gerar o plano. Tente novamente.";

  } catch (error) {
    console.error("Erro ao gerar plano catequético:", error);
    return "Ocorreu um erro ao conectar com a IA Pastoral. Verifique sua conexão.";
  }
};

