                value={etapa}
                onChange={(e) => setEtapa(e.target.value)}
                className="w-full border-gray-300 rounded-lg text-sm focus:ring-indigo-500 focus:border-indigo-500"
              >
                <option value="Pré-Eucaristia">Pré-Eucaristia</option>
                <option value="Eucaristia I">Eucaristia I</option>
                <option value="Eucaristia II">Eucaristia II</option>
                <option value="Crisma">Crisma</option>
                <option value="Catecumenato Adultos">Catecumenato Adultos</option>
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 uppercase mb-1">Tempo Litúrgico</label>
              <select 
                value={tempo}
                onChange={(e) => setTempo(e.target.value)}
                className="w-full border-gray-300 rounded-lg text-sm focus:ring-indigo-500 focus:border-indigo-500"
              >
                <option value="Tempo Comum">Tempo Comum</option>
                <option value="Advento">Advento</option>
                <option value="Natal">Natal</option>
                <option value="Quaresma">Quaresma</option>
                <option value="Páscoa">Páscoa</option>
                <option value="Pentecostes">Pentecostes</option>
              </select>
            </div>
          </div>

          <div className="relative">
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Ex: Sugira um encontro sobre os Dons do Espírito Santo com uma dinâmica para jovens agitados..."
              className="w-full p-4 pr-12 h-32 border border-gray-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none shadow-sm"
            />
            <button
              onClick={handleGenerate}
              disabled={isLoading || !prompt.trim()}
              className="absolute bottom-4 right-4 bg-indigo-600 text-white p-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md"
            >
              {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} />}
            </button>
          </div>
          <div className="mt-2 flex items-center text-xs text-indigo-600">
            <Info size={12} className="mr-1" />
            <span>A IA sugere temas baseados na Doutrina Católica. Revise sempre antes de aplicar.</span>
          </div>
        </div>

        {result && (
          <div className="p-8 bg-white animate-fade-in">
            <div className="prose prose-indigo max-w-none">
              <div className="flex items-center space-x-2 text-indigo-800 mb-6 pb-4 border-b border-indigo-100">
                <BookOpen size={24} />
                <h3 className="text-xl font-bold m-0">Sugestão de Encontro</h3>
              </div>
              <div className="whitespace-pre-wrap text-gray-700 leading-relaxed font-sans">
                {/* 
                  In a real app, use a Markdown renderer like react-markdown. 
                  For this constraint, we render raw text with whitespace handling 
                */}
                {result}
              </div>
            </div>
            <div className="mt-8 pt-6 border-t border-gray-100 flex justify-end space-x-3">
              <button className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Copiar Texto</button>
              <button className="px-4 py-2 text-sm bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
                Salvar no Planejamento
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AiPlanner;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import MeetingManager from './components/MeetingManager';
import PeopleManager from './components/PeopleManager';
import AiPlanner from './components/AiPlanner';
import { ViewState } from './types';
import { Church } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.ENCONTROS:
        return <MeetingManager />;
      case ViewState.CATEQUIZANDOS:
      case ViewState.CATEQUISTAS:
        return <PeopleManager />;
      case ViewState.IA_ASSISTANT:
        return <AiPlanner />;
      case ViewState.ESTRUTURA:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-12 bg-white rounded-xl border border-dashed border-gray-300">
            <Church size={64} className="mb-4 text-gray-200" />
