interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');

  // Update tab if prop changes
  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  const filteredCatequizandos = MOCK_CATEQUIZANDOS.filter(c => 
    c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredCatequistas = MOCK_CATEQUISTAS.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = MOCK_FAMILIAS.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.pai.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.mae.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    // Remove non-numeric characters
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center space-y-4 sm:space-y-0">
