            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button className="bg-church-600 text-white px-4 py-2 rounded-lg hover:bg-church-700 flex items-center font-medium whitespace-nowrap">
          <Plus size={20} className="mr-2" />
