  id: string;
  turma_id: string;
  nome_completo: string;
  data_nascimento: string;
  nome_responsavel: string;
  telefone_responsavel: string;
  sacramentos: {
    batismo: boolean;
    eucaristia: boolean;
    crisma: boolean;
  };
  observacoes_pastorais: string;
  familia_id?: string;
}

export interface Familia {
  id: string;
  sobrenome: string; // Ex: Família Silva
  pai: string;
  mae: string;
  casados_igreja: boolean;
  endereco: string;
