import React, { createContext, useContext, useState, ReactNode } from 'react';
import { 
  Catequizando, 
  Catequista, 
  Familia, 
  Encontro, 
  Presenca, 
  Turma, 
  Paroquia,
  UserRole
} from '../types';
import { 
  MOCK_CATEQUIZANDOS, 
  MOCK_CATEQUISTAS, 
  MOCK_FAMILIAS, 
  MOCK_ENCONTROS, 
  MOCK_PRESENCAS,
  MOCK_TURMAS,
  MOCK_PAROQUIA
} from '../constants';

interface DataContextType {
  paroquia: Paroquia;
  turmas: Turma[];
  catequizandos: Catequizando[];
  familias: Familia[];
  catequistas: Catequista[];
  encontros: Encontro[];
  presencas: Presenca[];

  // Actions
  addCatequizando: (data: Omit<Catequizando, 'id'>) => void;
  addFamilia: (data: Omit<Familia, 'id'>) => void;
  addCatequista: (data: Omit<Catequista, 'id'>) => void;
  addEncontro: (data: Omit<Encontro, 'id'>) => void;
  updatePresenca: (presenca: Presenca) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [catequizandos, setCatequizandos] = useState<Catequizando[]>(MOCK_CATEQUIZANDOS);
  const [familias, setFamilias] = useState<Familia[]>(MOCK_FAMILIAS);
  const [catequistas, setCatequistas] = useState<Catequista[]>(MOCK_CATEQUISTAS);
  const [encontros, setEncontros] = useState<Encontro[]>(MOCK_ENCONTROS);
  const [presencas, setPresencas] = useState<Presenca[]>(MOCK_PRESENCAS);

  // Static data for now, but could be dynamic later
  const turmas = MOCK_TURMAS;
  const paroquia = MOCK_PAROQUIA;

  const addCatequizando = (data: Omit<Catequizando, 'id'>) => {
    const newId = Date.now().toString();
    setCatequizandos([...catequizandos, { ...data, id: newId }]);
  };

  const addFamilia = (data: Omit<Familia, 'id'>) => {
    const newId = Date.now().toString();
    setFamilias([...familias, { ...data, id: newId }]);
  };

  const addCatequista = (data: Omit<Catequista, 'id'>) => {
    const newId = Date.now().toString();
    setCatequistas([...catequistas, { ...data, id: newId }]);
  };

  const addEncontro = (data: Omit<Encontro, 'id'>) => {
    const newId = Date.now().toString();
    setEncontros([...encontros, { ...data, id: newId }]);
  };

  const updatePresenca = (presenca: Presenca) => {
    setPresencas(prev => {
      const index = prev.findIndex(p => p.id === presenca.id);
      if (index >= 0) {
        const newPresencas = [...prev];
        newPresencas[index] = presenca;
        return newPresencas;
      } else {
        return [...prev, presenca];
      }
    });
  };

  return (
    <DataContext.Provider value={{
      paroquia,
      turmas,
      catequizandos,
      familias,
      catequistas,
      encontros,
      presencas,
      addCatequizando,
      addFamilia,
      addCatequista,
      addEncontro,
      updatePresenca
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import MeetingManager from './components/MeetingManager';
import PeopleManager from './components/PeopleManager';
import AiPlanner from './components/AiPlanner';
import Login from './components/Login';
import { ViewState } from './types';
import { Church } from 'lucide-react';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { DataProvider } from './contexts/DataContext';

// Main App Component with Auth Logic
const AuthenticatedApp: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { user } = useAuth();

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.ENCONTROS:
        return <MeetingManager />;
      case ViewState.CATEQUIZANDOS:
        return <PeopleManager initialTab="catequizandos" />;
      case ViewState.FAMILIAS:
        return <PeopleManager initialTab="familias" />;
      case ViewState.CATEQUISTAS:
        return <PeopleManager initialTab="catequistas" />;
      case ViewState.IA_ASSISTANT:
        return <AiPlanner />;
      case ViewState.ESTRUTURA:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-12 bg-white rounded-xl border border-dashed border-gray-300">
            <Church size={64} className="mb-4 text-gray-200" />
            <h3 className="text-xl font-medium text-gray-600">Estrutura Paroquial</h3>
            <p className="mt-2 text-center max-w-md">Gerenciamento de Diocese, Paróquia e Comunidades (Estrutura Hierárquica) estaria aqui no sistema completo.</p>
          </div>
        );
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

// Root Component deciding between Login and App
const Root: React.FC = () => {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? <AuthenticatedApp /> : <Login />;
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <DataProvider>
        <Root />
      </DataProvider>
    </AuthProvider>
  );
};

export default App;

