                      <button className="text-church-600 hover:text-church-800 font-medium">Perfil</button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>

          {/* Empty States */}
          {filteredCatequizandos.length === 0 && activeTab === 'catequizandos' && (
            <div className="p-8 text-center text-gray-500">Nenhum catequizando encontrado.</div>
          )}
          {filteredFamilias.length === 0 && activeTab === 'familias' && (
            <div className="p-8 text-center text-gray-500">Nenhuma família encontrada.</div>
          )}
        </div>
      </div>

      {/* MODAL DE CADASTRO */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
                <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                    <h3 className="font-bold capitalize">Novo Cadastro: {activeTab}</h3>
                    <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
                </div>
                <div className="p-6 overflow-y-auto">
                    <form onSubmit={handleSave} className="space-y-4">
