     telefone_responsavel: '',
     batismo: false,
     eucaristia: false,
     crisma: false
  });

  const [newFamilia, setNewFamilia] = useState({
     sobrenome: '',
     pai: '',
     mae: '',
     endereco: '',
     telefone_principal: '',
     casados_igreja: false,
     observacoes: ''
  });

