                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input type="text" required value={newCatequista.nome} onChange={e => setNewCatequista({...newCatequista, nome: e.target.value})} className="w-full border p-2 rounded-lg" />
