                        <span title="Eucaristia" className={`p-1 rounded ${cat.sacramentos.eucaristia ? 'bg-yellow-100 text-yellow-700' : 'bg-gray-100 text-gray-300'}`}><span className="text-xs font-bold px-1">E</span></span>
                        <span title="Crisma" className={`p-1 rounded ${cat.sacramentos.crisma ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-300'}`}><span className="text-xs font-bold px-1">C</span></span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Editar</button>
                    </td>
                  </tr>
                ))
              )}

              {/* --- TAB FAMILIAS --- */}
              {activeTab === 'familias' && (
                filteredFamilias.map(fam => (
                  <tr key={fam.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="w-8 h-8 rounded-full bg-teal-100 text-teal-600 flex items-center justify-center mr-3 text-xs font-bold">
                          <HeartHandshake size={14}/>
                        </div>
                        <div>
                          <div>{fam.sobrenome}</div>
                          <div className="text-xs text-gray-500 font-normal">
                             {fam.pai && fam.mae ? `${fam.pai} e ${fam.mae}` : fam.pai || fam.mae}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center space-x-2">
                         <span>{fam.telefone_principal}</span>
                         <button 
                            onClick={() => openWhatsApp(fam.telefone_principal)}
                            className="text-green-500 hover:text-green-600 p-1 rounded-full hover:bg-green-50 transition-colors"
                            title="Abrir WhatsApp"
                          >
                            <MessageCircle size={18} />
                          </button>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded text-xs font-medium ${fam.casados_igreja ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {fam.casados_igreja ? 'Casados na Igreja' : 'Acompanhamento'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      <div className="flex items-center">
                         <MapPin size={14} className="mr-1 text-gray-400"/>
                         <span className="truncate max-w-[150px]" title={fam.endereco}>{fam.endereco}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Detalhes</button>
                    </td>
                  </tr>
                ))
              )}

              {/* --- TAB CATEQUISTAS --- */}
              {activeTab === 'catequistas' && (
                filteredCatequistas.map(cat => (
                  <tr key={cat.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900 flex items-center">
                      <div className="w-8 h-8 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center mr-3 text-xs font-bold">
                        {cat.nome.charAt(0)}
                      </div>
                      {cat.nome}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-xs text-gray-500">{cat.email}</span>
                        <div className="flex items-center space-x-2">
                           <span className="text-xs text-gray-900">{cat.telefone}</span>
                           <button 
                            onClick={() => openWhatsApp(cat.telefone)}
                            className="text-green-500 hover:text-green-600 p-1 rounded-full hover:bg-green-50 transition-colors"
                            title="Abrir WhatsApp"
                          >
                            <MessageCircle size={14} />
                          </button>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">{cat.tempo_servico_anos} anos</td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Perfil</button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>

          {/* Empty States */}
          {filteredCatequizandos.length === 0 && activeTab === 'catequizandos' && (
            <div className="p-8 text-center text-gray-500">Nenhum catequizando encontrado com os filtros selecionados.</div>
          )}
          {filteredFamilias.length === 0 && activeTab === 'familias' && (
            <div className="p-8 text-center text-gray-500">Nenhuma família encontrada.</div>
          )}
        </div>
      </div>

      {/* MODAL DE CADASTRO */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
                <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                    <h3 className="font-bold capitalize">Novo Cadastro: {activeTab}</h3>
                    <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
                </div>
                <div className="p-6 overflow-y-auto">
                    <form onSubmit={handleSave} className="space-y-4">
                        {renderModalContent()}
                        <div className="pt-4">
                            <button 
                                type="submit"
                                className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
                            >
                                Salvar Cadastro
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default PeopleManager;

import React, { useState, useEffect } from 'react';
import { Search, Plus, User, Phone, Droplets, MessageCircle, HeartHandshake, MapPin, X, Filter } from 'lucide-react';
import { useData } from '../contexts/DataContext';

interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const { catequizandos, familias, catequistas, turmas, addCatequizando, addFamilia, addCatequista } = useData();

  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filters state
  const [filterEtapa, setFilterEtapa] = useState('');
  const [filterAno, setFilterAno] = useState('');

  // States for Forms
  const [newCatequizando, setNewCatequizando] = useState({
     nome_completo: '',
     data_nascimento: '',
     turma_id: turmas[0]?.id || '',
     nome_responsavel: '',
     telefone_responsavel: '',
     batismo: false,
     eucaristia: false,
     crisma: false
  });

  const [newFamilia, setNewFamilia] = useState({
     sobrenome: '',
     pai: '',
     mae: '',
     endereco: '',
     telefone_principal: '',
     casados_igreja: false,
     observacoes: ''
  });

  const [newCatequista, setNewCatequista] = useState({
    nome: '',
    email: '',
    telefone: '',
    tempo_servico_anos: 0,
    comunidade_id: 'c1' // Defaulting to c1 for now
  });

  // Update tab if prop changes
  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  // Extract unique filter options from Turmas
  const uniqueEtapas = Array.from(new Set(turmas.map(t => t.etapa_nome).filter(Boolean))) as string[];
  const uniqueAnos = Array.from(new Set(turmas.map(t => t.ano))).sort((a: number, b: number) => b - a);

  const filteredCatequizandos = catequizandos.filter(c => {
    const matchesSearch = c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase());

    // Find the student's class to check filters
    const turma = turmas.find(t => t.id === c.turma_id);

    const matchesEtapa = filterEtapa ? turma?.etapa_nome === filterEtapa : true;
    const matchesAno = filterAno ? turma?.ano.toString() === filterAno : true;

    return matchesSearch && matchesEtapa && matchesAno;
  });

  const filteredCatequistas = catequistas.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = familias.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.pai.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.mae.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catequizandos') {
        addCatequizando({
            ...newCatequizando,
            sacramentos: {
                batismo: newCatequizando.batismo,
                eucaristia: newCatequizando.eucaristia,
                crisma: newCatequizando.crisma
            },
            observacoes_pastorais: ''
        });
        // Reset form
        setNewCatequizando({
            nome_completo: '', data_nascimento: '', turma_id: turmas[0]?.id || '', 
            nome_responsavel: '', telefone_responsavel: '', 
            batismo: false, eucaristia: false, crisma: false
        });
    } else if (activeTab === 'familias') {
        addFamilia(newFamilia);
        setNewFamilia({ sobrenome: '', pai: '', mae: '', endereco: '', telefone_principal: '', casados_igreja: false, observacoes: '' });
    } else if (activeTab === 'catequistas') {
        addCatequista(newCatequista);
        setNewCatequista({ nome: '', email: '', telefone: '', tempo_servico_anos: 0, comunidade_id: 'c1' });
    }

    setIsModalOpen(false);
  };

  const renderModalContent = () => {
     if (activeTab === 'catequizandos') {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input type="text" required value={newCatequizando.nome_completo} onChange={e => setNewCatequizando({...newCatequizando, nome_completo: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Data Nascimento</label>
                        <input type="date" required value={newCatequizando.data_nascimento} onChange={e => setNewCatequizando({...newCatequizando, data_nascimento: e.target.value})} className="w-full border p-2 rounded-lg" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Turma</label>
                        <select value={newCatequizando.turma_id} onChange={e => setNewCatequizando({...newCatequizando, turma_id: e.target.value})} className="w-full border p-2 rounded-lg">
                           {turmas.map(t => <option key={t.id} value={t.id}>{t.etapa_nome}</option>)}
                        </select>
                    </div>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Responsável</label>
                   <input type="text" required value={newCatequizando.nome_responsavel} onChange={e => setNewCatequizando({...newCatequizando, nome_responsavel: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone/WhatsApp</label>
                   <input type="text" required value={newCatequizando.telefone_responsavel} onChange={e => setNewCatequizando({...newCatequizando, telefone_responsavel: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                    <span className="block text-sm font-medium text-gray-700 mb-2">Sacramentos Recebidos</span>
                    <div className="flex space-x-4">
                        <label className="flex items-center"><input type="checkbox" checked={newCatequizando.batismo} onChange={e => setNewCatequizando({...newCatequizando, batismo: e.target.checked})} className="mr-2"/> Batismo</label>
                        <label className="flex items-center"><input type="checkbox" checked={newCatequizando.eucaristia} onChange={e => setNewCatequizando({...newCatequizando, eucaristia: e.target.checked})} className="mr-2"/> Eucaristia</label>
                    </div>
                </div>
             </>
         );
     }

     if (activeTab === 'familias') {
        return (
            <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Sobrenome da Família (Ex: Família Silva)</label>
                   <input type="text" required value={newFamilia.sobrenome} onChange={e => setNewFamilia({...newFamilia, sobrenome: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Pai</label>
                       <input type="text" value={newFamilia.pai} onChange={e => setNewFamilia({...newFamilia, pai: e.target.value})} className="w-full border p-2 rounded-lg" />
                   </div>
                   <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Mãe</label>
                       <input type="text" value={newFamilia.mae} onChange={e => setNewFamilia({...newFamilia, mae: e.target.value})} className="w-full border p-2 rounded-lg" />
                   </div>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Endereço</label>
                   <input type="text" required value={newFamilia.endereco} onChange={e => setNewFamilia({...newFamilia, endereco: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone Principal</label>
                   <input type="text" required value={newFamilia.telefone_principal} onChange={e => setNewFamilia({...newFamilia, telefone_principal: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <label className="flex items-center"><input type="checkbox" checked={newFamilia.casados_igreja} onChange={e => setNewFamilia({...newFamilia, casados_igreja: e.target.checked})} className="mr-2"/> Casados na Igreja</label>
            </>
        );
     }

     if (activeTab === 'catequistas') {
        return (
            <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input type="text" required value={newCatequista.nome} onChange={e => setNewCatequista({...newCatequista, nome: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                   <input type="email" required value={newCatequista.email} onChange={e => setNewCatequista({...newCatequista, email: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                   <input type="text" required value={newCatequista.telefone} onChange={e => setNewCatequista({...newCatequista, telefone: e.target.value})} className="w-full border p-2 rounded-lg" />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tempo de Serviço (Anos)</label>
                   <input type="number" required value={newCatequista.tempo_servico_anos} onChange={e => setNewCatequista({...newCatequista, tempo_servico_anos: parseInt(e.target.value) || 0})} className="w-full border p-2 rounded-lg" />
                </div>
            </>
        );
     }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center space-y-4 sm:space-y-0">
        <h2 className="text-2xl font-bold text-gray-900">Pessoas & Famílias</h2>
        <div className="flex bg-gray-200 p-1 rounded-lg overflow-x-auto">
          <button 
            onClick={() => setActiveTab('catequizandos')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'catequizandos' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-gray-900'}`}
          >
            Catequizandos
          </button>
          <button 
            onClick={() => setActiveTab('familias')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'familias' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-gray-900'}`}
          >
            Famílias
          </button>
          <button 
            onClick={() => setActiveTab('catequistas')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'catequistas' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-gray-900'}`}
          >
            Catequistas
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text"
            placeholder={`Buscar em ${activeTab}...`}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-church-500 focus:border-church-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {activeTab === 'catequizandos' && (
          <div className="flex gap-2">
            <select 
              value={filterEtapa} 
              onChange={(e) => setFilterEtapa(e.target.value)}
              className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-church-500 focus:border-church-500 bg-white"
            >
              <option value="">Todas as Etapas</option>
              {uniqueEtapas.map(e => <option key={e} value={e}>{e}</option>)}
            </select>

            <select 
              value={filterAno} 
              onChange={(e) => setFilterAno(e.target.value)}
              className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-church-500 focus:border-church-500 bg-white"
            >
              <option value="">Todos os Anos</option>
              {uniqueAnos.map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>
        )}

        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-church-600 text-white px-4 py-2 rounded-lg hover:bg-church-700 flex items-center font-medium whitespace-nowrap justify-center"
        >
          <Plus size={20} className="mr-2" />
          Novo Cadastro
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-500">
            <thead className="bg-gray-50 text-xs uppercase text-gray-700">
              <tr>
                <th className="px-6 py-4 font-semibold">Nome / Identificação</th>
                <th className="px-6 py-4 font-semibold">Contato</th>

                {activeTab === 'catequizandos' && (
                  <>
                    <th className="px-6 py-4 font-semibold">Responsável</th>
                    <th className="px-6 py-4 font-semibold text-center">Sacramentos</th>
                  </>
                )}

                {activeTab === 'familias' && (
                  <>
                     <th className="px-6 py-4 font-semibold">Situação Matrimonial</th>
                     <th className="px-6 py-4 font-semibold">Endereço</th>
                  </>
                )}

                {activeTab === 'catequistas' && (
                   <th className="px-6 py-4 font-semibold">Tempo de Serviço</th>
                )}
                <th className="px-6 py-4 font-semibold text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">

              {/* --- TAB CATEQUIZANDOS --- */}
              {activeTab === 'catequizandos' && (
                filteredCatequizandos.map(cat => (
                  <tr key={cat.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900 flex items-center">
                      <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center mr-3 text-xs font-bold">
                        {cat.nome_completo.charAt(0)}
                      </div>
                      <div>
                        {cat.nome_completo}
                        <div className="text-xs text-gray-400 font-normal">
                          {turmas.find(t => t.id === cat.turma_id)?.etapa_nome} ({turmas.find(t => t.id === cat.turma_id)?.ano})
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center space-x-2">
                        <span className="text-gray-600">{cat.telefone_responsavel}</span>
                        <button 
                          onClick={() => openWhatsApp(cat.telefone_responsavel)}
                          className="text-green-500 hover:text-green-600 p-1 rounded-full hover:bg-green-50 transition-colors"
                          title="Abrir WhatsApp"
                        >
                          <MessageCircle size={18} />
                        </button>
                      </div>
                    </td>
                    <td className="px-6 py-4">{cat.nome_responsavel}</td>
                    <td className="px-6 py-4">
                      <div className="flex justify-center space-x-2">
                        <span title="Batismo" className={`p-1 rounded ${cat.sacramentos.batismo ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-300'}`}><Droplets size={16}/></span>
                        <span title="Eucaristia" className={`p-1 rounded ${cat.sacramentos.eucaristia ? 'bg-yellow-100 text-yellow-700' : 'bg-gray-100 text-gray-300'}`}><span className="text-xs font-bold px-1">E</span></span>
                        <span title="Crisma" className={`p-1 rounded ${cat.sacramentos.crisma ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-300'}`}><span className="text-xs font-bold px-1">C</span></span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Editar</button>
                    </td>
                  </tr>
                ))
              )}

              {/* --- TAB FAMILIAS --- */}
              {activeTab === 'familias' && (
                filteredFamilias.map(fam => (
                  <tr key={fam.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900">
                      <div className="flex items-center">
                        <div className="w-8 h-8 rounded-full bg-teal-100 text-teal-600 flex items-center justify-center mr-3 text-xs font-bold">
                          <HeartHandshake size={14}/>
                        </div>
                        <div>
                          <div>{fam.sobrenome}</div>
                          <div className="text-xs text-gray-500 font-normal">
                             {fam.pai && fam.mae ? `${fam.pai} e ${fam.mae}` : fam.pai || fam.mae}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center space-x-2">
                         <span>{fam.telefone_principal}</span>
                         <button 
                            onClick={() => openWhatsApp(fam.telefone_principal)}
                            className="text-green-500 hover:text-green-600 p-1 rounded-full hover:bg-green-50 transition-colors"
                            title="Abrir WhatsApp"
                          >
                            <MessageCircle size={18} />
                          </button>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded text-xs font-medium ${fam.casados_igreja ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'}`}>
                        {fam.casados_igreja ? 'Casados na Igreja' : 'Acompanhamento'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      <div className="flex items-center">
                         <MapPin size={14} className="mr-1 text-gray-400"/>
                         <span className="truncate max-w-[150px]" title={fam.endereco}>{fam.endereco}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Detalhes</button>
                    </td>
                  </tr>
                ))
              )}

              {/* --- TAB CATEQUISTAS --- */}
              {activeTab === 'catequistas' && (
                filteredCatequistas.map(cat => (
                  <tr key={cat.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-gray-900 flex items-center">
                      <div className="w-8 h-8 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center mr-3 text-xs font-bold">
                        {cat.nome.charAt(0)}
                      </div>
                      {cat.nome}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-xs text-gray-500">{cat.email}</span>
                        <div className="flex items-center space-x-2">
                           <span className="text-xs text-gray-900">{cat.telefone}</span>
                           <button 
                            onClick={() => openWhatsApp(cat.telefone)}
                            className="text-green-500 hover:text-green-600 p-1 rounded-full hover:bg-green-50 transition-colors"
                            title="Abrir WhatsApp"
                          >
                            <MessageCircle size={14} />
                          </button>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">{cat.tempo_servico_anos} anos</td>
                    <td className="px-6 py-4 text-right">
                      <button className="text-church-600 hover:text-church-800 font-medium">Perfil</button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>

          {/* Empty States */}
          {filteredCatequizandos.length === 0 && activeTab === 'catequizandos' && (
            <div className="p-8 text-center text-gray-500">Nenhum catequizando encontrado com os filtros selecionados.</div>
          )}
          {filteredFamilias.length === 0 && activeTab === 'familias' && (
            <div className="p-8 text-center text-gray-500">Nenhuma família encontrada.</div>
          )}
        </div>
      </div>

      {/* MODAL DE CADASTRO */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
                <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                    <h3 className="font-bold capitalize">Novo Cadastro: {activeTab}</h3>
                    <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
                </div>
                <div className="p-6 overflow-y-auto">
                    <form onSubmit={handleSave} className="space-y-4">
                        {renderModalContent()}
                        <div className="pt-4">
                            <button 
                                type="submit"
                                className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
                            >
                                Salvar Cadastro
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default PeopleManager;

import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Search, Plus, User, Droplets, MessageCircle, HeartHandshake, MapPin, X, Filter } from 'lucide-react';
import { useData } from '../contexts/DataContext';

interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const { catequizandos, familias, catequistas, turmas, addCatequizando, addFamilia, addCatequista } = useData();

  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filters state
  const [filterEtapa, setFilterEtapa] = useState('');
  const [filterAno, setFilterAno] = useState('');

  // States for Forms
  const [newCatequizando, setNewCatequizando] = useState({
     nome_completo: '',
     data_nascimento: '',
     turma_id: turmas[0]?.id || '',
     nome_responsavel: '',
     telefone_responsavel: '',
     batismo: false,
     eucaristia: false,
     crisma: false
  });

  const [newFamilia, setNewFamilia] = useState({
     sobrenome: '',
     pai: '',
     mae: '',
     endereco: '',
     telefone_principal: '',
     casados_igreja: false,
     observacoes: ''
  });

  const [newCatequista, setNewCatequista] = useState({
    nome: '',
    email: '',
    telefone: '',
    tempo_servico_anos: 0,
    comunidade_id: 'c1' // Defaulting to c1 for now
  });

  // Update tab if prop changes
  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  // Extract unique filter options from Turmas
  const uniqueEtapas = Array.from(new Set(turmas.map(t => t.etapa_nome).filter(Boolean))) as string[];
  const uniqueAnos = Array.from(new Set(turmas.map(t => t.ano))).sort((a: number, b: number) => b - a);

  const filteredCatequizandos = catequizandos.filter(c => {
    const matchesSearch = c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase());

    // Find the student's class to check filters
    const turma = turmas.find(t => t.id === c.turma_id);

    const matchesEtapa = filterEtapa ? turma?.etapa_nome === filterEtapa : true;
    const matchesAno = filterAno ? turma?.ano.toString() === filterAno : true;

    return matchesSearch && matchesEtapa && matchesAno;
  });

  const filteredCatequistas = catequistas.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = familias.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.pai.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.mae.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catequizandos') {
        addCatequizando({
            ...newCatequizando,
            sacramentos: {
                batismo: newCatequizando.batismo,
                eucaristia: newCatequizando.eucaristia,
                crisma: newCatequizando.crisma
            },
            observacoes_pastorais: ''
        });
        // Reset form
        setNewCatequizando({
            nome_completo: '', data_nascimento: '', turma_id: turmas[0]?.id || '', 
            nome_responsavel: '', telefone_responsavel: '', 
            batismo: false, eucaristia: false, crisma: false
        });
    } else if (activeTab === 'familias') {
        addFamilia(newFamilia);
        setNewFamilia({ sobrenome: '', pai: '', mae: '', endereco: '', telefone_principal: '', casados_igreja: false, observacoes: '' });
    } else if (activeTab === 'catequistas') {
        addCatequista(newCatequista);
        setNewCatequista({ nome: '', email: '', telefone: '', tempo_servico_anos: 0, comunidade_id: 'c1' });
    }

    setIsModalOpen(false);
  };

  const renderModalContent = () => {
     if (activeTab === 'catequizandos') {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input 
                      type="text" 
                      required 
                      value={newCatequizando.nome_completo} 
                      onChange={e => setNewCatequizando({...newCatequizando, nome_completo: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data de Nascimento</label>
                   <input 
                      type="date" 
                      required 
                      value={newCatequizando.data_nascimento} 
                      onChange={e => setNewCatequizando({...newCatequizando, data_nascimento: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Turma</label>
                   <select
                      value={newCatequizando.turma_id}
                      onChange={e => setNewCatequizando({...newCatequizando, turma_id: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      {turmas.map(t => (
                        <option key={t.id} value={t.id}>{t.etapa_nome} - {t.dia_encontro}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Responsável</label>
                   <input 
                      type="text" 
                      required 
                      value={newCatequizando.nome_responsavel} 
                      onChange={e => setNewCatequizando({...newCatequizando, nome_responsavel: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                   <input 
                      type="tel" 
                      required 
                      value={newCatequizando.telefone_responsavel} 
                      onChange={e => setNewCatequizando({...newCatequizando, telefone_responsavel: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div className="flex space-x-4 mt-2">
                   <label className="flex items-center space-x-2">
                     <input type="checkbox" checked={newCatequizando.batismo} onChange={e => setNewCatequizando({...newCatequizando, batismo: e.target.checked})} />
                     <span className="text-sm">Batismo</span>
                   </label>
                   <label className="flex items-center space-x-2">
                     <input type="checkbox" checked={newCatequizando.eucaristia} onChange={e => setNewCatequizando({...newCatequizando, eucaristia: e.target.checked})} />
                     <span className="text-sm">Eucaristia</span>
                   </label>
                </div>
             </>
         );
     } else if (activeTab === 'familias') {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Sobrenome da Família</label>
                   <input type="text" required value={newFamilia.sobrenome} onChange={e => setNewFamilia({...newFamilia, sobrenome: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none" placeholder="Ex: Família Silva"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Pai</label>
                   <input type="text" value={newFamilia.pai} onChange={e => setNewFamilia({...newFamilia, pai: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Mãe</label>
                   <input type="text" required value={newFamilia.mae} onChange={e => setNewFamilia({...newFamilia, mae: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone Principal</label>
                   <input type="tel" required value={newFamilia.telefone_principal} onChange={e => setNewFamilia({...newFamilia, telefone_principal: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <label className="flex items-center space-x-2 mt-2">
                     <input type="checkbox" checked={newFamilia.casados_igreja} onChange={e => setNewFamilia({...newFamilia, casados_igreja: e.target.checked})} />
                     <span className="text-sm">Casados na Igreja?</span>
                </label>
             </>
         );
     } else {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input type="text" required value={newCatequista.nome} onChange={e => setNewCatequista({...newCatequista, nome: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">E-mail</label>
                   <input type="email" required value={newCatequista.email} onChange={e => setNewCatequista({...newCatequista, email: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                   <input type="tel" required value={newCatequista.telefone} onChange={e => setNewCatequista({...newCatequista, telefone: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tempo de Serviço (Anos)</label>
                   <input type="number" required value={newCatequista.tempo_servico_anos} onChange={e => setNewCatequista({...newCatequista, tempo_servico_anos: parseInt(e.target.value)})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
             </>
         );
     }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-gray-900 capitalize">{activeTab}</h2>
           <p className="text-gray-500 text-sm">Gerenciamento de {activeTab}</p>
        </div>
        <div className="flex items-center space-x-2 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-church-500 outline-none text-sm"
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center justify-center space-x-2 bg-church-600 text-white px-4 py-2 rounded-lg hover:bg-church-700 transition-colors"
          >
            <Plus size={18} />
            <span className="hidden md:inline">Adicionar</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        {/* Tabs */}
        <div className="flex border-b border-gray-200 overflow-x-auto">
           {(['catequizandos', 'familias', 'catequistas'] as const).map(tab => (
             <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-6 py-3 font-medium text-sm whitespace-nowrap ${activeTab === tab ? 'border-b-2 border-church-600 text-church-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
             </button>
           ))}
        </div>

        {/* Filters for Catequizandos */}
        {activeTab === 'catequizandos' && (
           <div className="p-4 bg-gray-50 border-b border-gray-200 flex flex-wrap gap-2">
              <div className="flex items-center text-sm text-gray-500 mr-2">
                 <Filter size={16} className="mr-1" />
                 Filtros:
              </div>
              <select 
                value={filterEtapa} 
                onChange={e => setFilterEtapa(e.target.value)}
                className="text-sm border-gray-300 rounded-md focus:ring-church-500 focus:border-church-500"
              >
                 <option value="">Todas Etapas</option>
                 {uniqueEtapas.map(e => <option key={e} value={e}>{e}</option>)}
              </select>
              <select 
                value={filterAno} 
                onChange={e => setFilterAno(e.target.value)}
                className="text-sm border-gray-300 rounded-md focus:ring-church-500 focus:border-church-500"
              >
                 <option value="">Todos Anos</option>
                 {uniqueAnos.map(a => <option key={a} value={a}>{a}</option>)}
              </select>
           </div>
        )}

        {/* List Content */}
        <div className="divide-y divide-gray-100">
          {activeTab === 'catequizandos' && filteredCatequizandos.map(item => (
             <div key={item.id} className="p-4 flex flex-col md:flex-row justify-between items-start md:items-center hover:bg-gray-50">
               <div className="flex items-center space-x-4 mb-2 md:mb-0">
                  <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold">
                     {item.nome_completo.charAt(0)}
                  </div>
                  <div>
                     <p className="font-semibold text-gray-900">{item.nome_completo}</p>
                     <p className="text-xs text-gray-500">
                        Nasc: {new Date(item.data_nascimento).toLocaleDateString()} • Resp: {item.nome_responsavel}
                     </p>
                  </div>
               </div>
               <div className="flex items-center space-x-2">
                  <div className="flex space-x-1 mr-4">
                     {item.sacramentos.batismo && <span title="Batizado" className="bg-blue-100 text-blue-600 p-1 rounded"><Droplets size={14}/></span>}
                     {item.sacramentos.eucaristia && <span title="1ª Eucaristia" className="bg-yellow-100 text-yellow-600 p-1 rounded"><User size={14}/></span>}
                  </div>
                  <button onClick={() => openWhatsApp(item.telefone_responsavel)} className="text-green-600 hover:bg-green-50 p-2 rounded-full transition-colors" title="WhatsApp Responsável">
                     <MessageCircle size={20} />
                  </button>
               </div>
             </div>
          ))}

          {activeTab === 'familias' && filteredFamilias.map(item => (
             <div key={item.id} className="p-4 flex flex-col md:flex-row justify-between items-start md:items-center hover:bg-gray-50">
               <div className="flex items-center space-x-4 mb-2 md:mb-0">
                  <div className="w-10 h-10 rounded-full bg-pink-100 text-pink-600 flex items-center justify-center font-bold">
                     <HeartHandshake size={20} />
                  </div>
                  <div>
                     <p className="font-semibold text-gray-900">{item.sobrenome}</p>
                     <p className="text-xs text-gray-500">
                        {item.pai && `Pai: ${item.pai} • `} Mãe: {item.mae}
                     </p>
                  </div>
               </div>
               <div className="flex items-center space-x-2 text-sm text-gray-500">
                  <MapPin size={16} className="mr-1" />
                  <span className="truncate max-w-[200px]">{item.endereco}</span>
                  <button onClick={() => openWhatsApp(item.telefone_principal)} className="ml-2 text-green-600 hover:bg-green-50 p-2 rounded-full transition-colors">
                     <MessageCircle size={20} />
                  </button>
               </div>
             </div>
          ))}

          {activeTab === 'catequistas' && filteredCatequistas.map(item => (
             <div key={item.id} className="p-4 flex flex-col md:flex-row justify-between items-start md:items-center hover:bg-gray-50">
               <div className="flex items-center space-x-4 mb-2 md:mb-0">
                  <div className="w-10 h-10 rounded-full bg-green-100 text-green-600 flex items-center justify-center font-bold">
                     {item.nome.charAt(0)}
                  </div>
                  <div>
                     <p className="font-semibold text-gray-900">{item.nome}</p>
                     <p className="text-xs text-gray-500">
                        {item.email} • {item.tempo_servico_anos} anos de serviço
                     </p>
                  </div>
               </div>
               <button onClick={() => openWhatsApp(item.telefone)} className="text-green-600 hover:bg-green-50 p-2 rounded-full transition-colors">
                  <MessageCircle size={20} />
               </button>
             </div>
          ))}

          {/* Empty States */}
          {activeTab === 'catequizandos' && filteredCatequizandos.length === 0 && <p className="p-8 text-center text-gray-500">Nenhum catequizando encontrado.</p>}
          {activeTab === 'familias' && filteredFamilias.length === 0 && <p className="p-8 text-center text-gray-500">Nenhuma família encontrada.</p>}
          {activeTab === 'catequistas' && filteredCatequistas.length === 0 && <p className="p-8 text-center text-gray-500">Nenhum catequista encontrado.</p>}
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
         <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden max-h-[90vh] flex flex-col">
               <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                  <h3 className="font-bold">Novo {activeTab.slice(0, -1)}</h3>
                  <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
               </div>
               <form onSubmit={handleSave} className="p-6 space-y-4 overflow-y-auto">
                  {renderModalContent()}
                  <button 
                    type="submit"
                    className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
                  >
                     Salvar Cadastro
                  </button>
               </form>
            </div>
         </div>
      )}
    </div>
  );
};

export default PeopleManager;

import React, { useState, useEffect } from 'react';
import { Search, Plus, User, Droplets, MessageCircle, HeartHandshake, MapPin, X, Filter } from 'lucide-react';
import { useData } from '../contexts/DataContext';

interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const { catequizandos, familias, catequistas, turmas, addCatequizando, addFamilia, addCatequista } = useData();

  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filters state
  const [filterEtapa, setFilterEtapa] = useState('');
  const [filterAno, setFilterAno] = useState('');

  // States for Forms
  const [newCatequizando, setNewCatequizando] = useState({
     nome_completo: '',
     data_nascimento: '',
     turma_id: turmas[0]?.id || '',
     familia_id: '',
     nome_responsavel: '',
     telefone_responsavel: '',
     batismo: false,
     eucaristia: false,
     crisma: false
  });

  const [newFamilia, setNewFamilia] = useState({
     sobrenome: '',
     pai: '',
     mae: '',
     endereco: '',
     telefone_principal: '',
     casados_igreja: false,
     observacoes: ''
  });

  const [newCatequista, setNewCatequista] = useState({
    nome: '',
    email: '',
    telefone: '',
    tempo_servico_anos: 0,
    comunidade_id: 'c1' // Defaulting to c1 for now
  });

  // Update tab if prop changes
  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  // Extract unique filter options from Turmas
  const uniqueEtapas = Array.from(new Set(turmas.map(t => t.etapa_nome).filter(Boolean))) as string[];
  const uniqueAnos = Array.from(new Set(turmas.map(t => t.ano))).sort((a: number, b: number) => b - a);

  const filteredCatequizandos = catequizandos.filter(c => {
    const matchesSearch = c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase());

    // Find the student's class to check filters
    const turma = turmas.find(t => t.id === c.turma_id);

    const matchesEtapa = filterEtapa ? turma?.etapa_nome === filterEtapa : true;
    const matchesAno = filterAno ? turma?.ano.toString() === filterAno : true;

    return matchesSearch && matchesEtapa && matchesAno;
  });

  const filteredCatequistas = catequistas.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = familias.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.pai.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.mae.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();

    if (activeTab === 'catequizandos') {
        addCatequizando({
            ...newCatequizando,
            familia_id: newCatequizando.familia_id || undefined,
            sacramentos: {
                batismo: newCatequizando.batismo,
                eucaristia: newCatequizando.eucaristia,
                crisma: newCatequizando.crisma
            },
            observacoes_pastorais: ''
        });
        // Reset form
        setNewCatequizando({
            nome_completo: '', data_nascimento: '', turma_id: turmas[0]?.id || '', 
            familia_id: '',
            nome_responsavel: '', telefone_responsavel: '', 
            batismo: false, eucaristia: false, crisma: false
        });
    } else if (activeTab === 'familias') {
        addFamilia(newFamilia);
        setNewFamilia({ sobrenome: '', pai: '', mae: '', endereco: '', telefone_principal: '', casados_igreja: false, observacoes: '' });
    } else if (activeTab === 'catequistas') {
        addCatequista(newCatequista);
        setNewCatequista({ nome: '', email: '', telefone: '', tempo_servico_anos: 0, comunidade_id: 'c1' });
    }

    setIsModalOpen(false);
  };

  const renderModalContent = () => {
     if (activeTab === 'catequizandos') {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input 
                      type="text" 
                      required 
                      value={newCatequizando.nome_completo} 
                      onChange={e => setNewCatequizando({...newCatequizando, nome_completo: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data de Nascimento</label>
                   <input 
                      type="date" 
                      required 
                      value={newCatequizando.data_nascimento} 
                      onChange={e => setNewCatequizando({...newCatequizando, data_nascimento: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Turma</label>
                   <select
                      value={newCatequizando.turma_id}
                      onChange={e => setNewCatequizando({...newCatequizando, turma_id: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      {turmas.map(t => (
                        <option key={t.id} value={t.id}>{t.etapa_nome} - {t.dia_encontro}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Vincular Família (Opcional)</label>
                   <select
                      value={newCatequizando.familia_id}
                      onChange={e => setNewCatequizando({...newCatequizando, familia_id: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      <option value="">Sem vínculo familiar</option>
                      {familias.map(f => (
                        <option key={f.id} value={f.id}>{f.sobrenome} ({f.pai || f.mae})</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Responsável</label>
                   <input 
                      type="text" 
                      required 
                      value={newCatequizando.nome_responsavel} 
                      onChange={e => setNewCatequizando({...newCatequizando, nome_responsavel: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                   <input 
                      type="tel" 
                      required 
                      value={newCatequizando.telefone_responsavel} 
                      onChange={e => setNewCatequizando({...newCatequizando, telefone_responsavel: e.target.value})} 
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div className="flex space-x-4 mt-2">
                   <label className="flex items-center space-x-2">
                     <input type="checkbox" checked={newCatequizando.batismo} onChange={e => setNewCatequizando({...newCatequizando, batismo: e.target.checked})} />
                     <span className="text-sm">Batismo</span>
                   </label>
                   <label className="flex items-center space-x-2">
                     <input type="checkbox" checked={newCatequizando.eucaristia} onChange={e => setNewCatequizando({...newCatequizando, eucaristia: e.target.checked})} />
                     <span className="text-sm">Eucaristia</span>
                   </label>
                   <label className="flex items-center space-x-2">
                     <input type="checkbox" checked={newCatequizando.crisma} onChange={e => setNewCatequizando({...newCatequizando, crisma: e.target.checked})} />
                     <span className="text-sm">Crisma</span>
                   </label>
                </div>
             </>
         );
     } else if (activeTab === 'familias') {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Sobrenome da Família</label>
                   <input type="text" required value={newFamilia.sobrenome} onChange={e => setNewFamilia({...newFamilia, sobrenome: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none" placeholder="Ex: Família Silva"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Pai</label>
                   <input type="text" value={newFamilia.pai} onChange={e => setNewFamilia({...newFamilia, pai: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Mãe</label>
                   <input type="text" required value={newFamilia.mae} onChange={e => setNewFamilia({...newFamilia, mae: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone Principal</label>
                   <input type="tel" required value={newFamilia.telefone_principal} onChange={e => setNewFamilia({...newFamilia, telefone_principal: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <label className="flex items-center space-x-2 mt-2">
                     <input type="checkbox" checked={newFamilia.casados_igreja} onChange={e => setNewFamilia({...newFamilia, casados_igreja: e.target.checked})} />
                     <span className="text-sm">Casados na Igreja?</span>
                </label>
             </>
         );
     } else {
         return (
             <>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                   <input type="text" required value={newCatequista.nome} onChange={e => setNewCatequista({...newCatequista, nome: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">E-mail</label>
                   <input type="email" required value={newCatequista.email} onChange={e => setNewCatequista({...newCatequista, email: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                   <input type="tel" required value={newCatequista.telefone} onChange={e => setNewCatequista({...newCatequista, telefone: e.target.value})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tempo de Serviço (Anos)</label>
                   <input type="number" required value={newCatequista.tempo_servico_anos} onChange={e => setNewCatequista({...newCatequista, tempo_servico_anos: parseInt(e.target.value)})} className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"/>
                </div>
             </>
         );
     }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">
             {activeTab === 'catequizandos' ? 'Gestão de Catequizandos' : 
              activeTab === 'familias' ? 'Registro de Famílias' : 'Equipe de Catequese'}
           </h2>
           <p className="text-gray-500 text-sm">
             {activeTab === 'catequizandos' ? 'Acompanhe o desenvolvimento e sacramentos.' : 
              activeTab === 'familias' ? 'Dados dos pais e responsáveis.' : 'Coordenadores e catequistas da paróquia.'}
           </p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-church-600 text-white px-4 py-2 rounded-lg font-semibold flex items-center hover:bg-church-700 transition-colors"
        >
          <Plus size={20} className="mr-2" />
          Novo Cadastro
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center mb-4">
          <div className="flex space-x-2 bg-gray-100 p-1 rounded-lg">
             <button onClick={() => setActiveTab('catequizandos')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'catequizandos' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-church-700'}`}>Catequizandos</button>
             <button onClick={() => setActiveTab('familias')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'familias' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-church-700'}`}>Famílias</button>
             <button onClick={() => setActiveTab('catequistas')} className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === 'catequistas' ? 'bg-white shadow text-church-900' : 'text-gray-600 hover:text-church-700'}`}>Equipe</button>
          </div>

          <div className="flex flex-1 w-full md:w-auto md:max-w-md space-x-2">
            <div className="relative flex-1">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
               <input 
                 type="text" 
                 placeholder="Buscar por nome..." 
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-church-500 focus:border-transparent outline-none text-sm"
               />
            </div>
            {activeTab === 'catequizandos' && (
              <div className="flex space-x-2">
                <select value={filterEtapa} onChange={(e) => setFilterEtapa(e.target.value)} className="border border-gray-300 rounded-lg px-2 py-2 text-sm outline-none focus:border-church-500">
                  <option value="">Todas Etapas</option>
                  {uniqueEtapas.map(etapa => <option key={etapa} value={etapa}>{etapa}</option>)}
                </select>
                <select value={filterAno} onChange={(e) => setFilterAno(e.target.value)} className="border border-gray-300 rounded-lg px-2 py-2 text-sm outline-none focus:border-church-500">
                   <option value="">Ano</option>
                   {uniqueAnos.map(ano => <option key={ano} value={ano}>{ano}</option>)}
                </select>
              </div>
            )}
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-600">
            <thead className="bg-gray-50 text-gray-700 font-semibold uppercase text-xs">
              <tr>
                <th className="px-4 py-3 rounded-l-lg">Nome</th>
                {activeTab === 'catequizandos' && (
                  <>
                    <th className="px-4 py-3">Idade</th>
                    <th className="px-4 py-3">Turma/Etapa</th>
                    <th className="px-4 py-3">Responsável</th>
                    <th className="px-4 py-3 text-center">Sacramentos</th>
                  </>
                )}
                {activeTab === 'familias' && (
                   <>
                    <th className="px-4 py-3">Pai/Mãe</th>
                    <th className="px-4 py-3">Situação Matrimonial</th>
                    <th className="px-4 py-3">Endereço</th>
                   </>
                )}
                {activeTab === 'catequistas' && (
                   <>
                    <th className="px-4 py-3">Email</th>
                    <th className="px-4 py-3">Tempo Serviço</th>
                   </>
                )}
                <th className="px-4 py-3 rounded-r-lg text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {activeTab === 'catequizandos' && filteredCatequizandos.map(student => {
                const turma = turmas.find(t => t.id === student.turma_id);
                const age = new Date().getFullYear() - new Date(student.data_nascimento).getFullYear();
                return (
                  <tr key={student.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3 font-medium text-gray-900 flex items-center">
                       <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-700 flex items-center justify-center mr-3 font-bold text-xs">
                         {student.nome_completo.charAt(0)}
                       </div>
                       {student.nome_completo}
                    </td>
                    <td className="px-4 py-3">{age} anos</td>
                    <td className="px-4 py-3">
                      <span className="bg-blue-50 text-blue-700 px-2 py-0.5 rounded text-xs border border-blue-100">
                        {turma?.etapa_nome || 'N/A'}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                       <div className="flex flex-col">
                          <span>{student.nome_responsavel}</span>
                          <span className="text-xs text-gray-400">{student.telefone_responsavel}</span>
                       </div>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex justify-center space-x-1">
                         <Droplets size={16} className={student.sacramentos.batismo ? "text-blue-500" : "text-gray-300"} title="Batismo" />
                         <div className="w-4 h-4 rounded-full border border-current flex items-center justify-center text-[10px] font-bold text-amber-500 opacity-80" title="Eucaristia">
                           {student.sacramentos.eucaristia ? 'E' : ''}
                         </div>
                         <div className="w-4 h-4 rounded-full border border-current flex items-center justify-center text-[10px] font-bold text-red-500 opacity-80" title="Crisma">
                           {student.sacramentos.crisma ? 'C' : ''}
                         </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 text-right">
                       <button onClick={() => openWhatsApp(student.telefone_responsavel)} className="text-green-600 hover:bg-green-50 p-1.5 rounded-full transition-colors" title="Contato WhatsApp">
                          <MessageCircle size={18} />
                       </button>
                    </td>
                  </tr>
                );
              })}

              {activeTab === 'familias' && filteredFamilias.map(familia => (
                <tr key={familia.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3 font-medium text-gray-900">{familia.sobrenome}</td>
                    <td className="px-4 py-3">
                       <div className="flex flex-col text-xs">
                          {familia.pai && <span><User size={12} className="inline mr-1"/>{familia.pai}</span>}
                          {familia.mae && <span><User size={12} className="inline mr-1"/>{familia.mae}</span>}
                       </div>
                    </td>
                    <td className="px-4 py-3">
                       {familia.casados_igreja ? 
                         <span className="text-green-600 text-xs flex items-center"><HeartHandshake size={12} className="mr-1"/> Casados na Igreja</span> : 
                         <span className="text-orange-500 text-xs">Não Casados na Igreja</span>
                       }
                    </td>
                    <td className="px-4 py-3 text-xs flex items-center text-gray-500">
                       <MapPin size={12} className="mr-1"/> {familia.endereco}
                    </td>
                    <td className="px-4 py-3 text-right">
                       <button onClick={() => openWhatsApp(familia.telefone_principal)} className="text-green-600 hover:bg-green-50 p-1.5 rounded-full transition-colors">
                          <MessageCircle size={18} />
                       </button>
                    </td>
                </tr>
              ))}

              {activeTab === 'catequistas' && filteredCatequistas.map(cat => (
                 <tr key={cat.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3 font-medium text-gray-900 flex items-center">
                       <div className="w-8 h-8 rounded-full bg-purple-100 text-purple-700 flex items-center justify-center mr-3 font-bold text-xs">
                         {cat.nome.charAt(0)}
                       </div>
                       {cat.nome}
                    </td>
                    <td className="px-4 py-3 text-gray-500">{cat.email}</td>
                    <td className="px-4 py-3 text-gray-500">{cat.tempo_servico_anos} anos</td>
                    <td className="px-4 py-3 text-right">
                       <button onClick={() => openWhatsApp(cat.telefone)} className="text-green-600 hover:bg-green-50 p-1.5 rounded-full transition-colors">
                          <MessageCircle size={18} />
                       </button>
                    </td>
                 </tr>
              ))}
            </tbody>
          </table>

          {((activeTab === 'catequizandos' && filteredCatequizandos.length === 0) || 
            (activeTab === 'familias' && filteredFamilias.length === 0) ||
            (activeTab === 'catequistas' && filteredCatequistas.length === 0)) && (
             <div className="p-8 text-center text-gray-400">
                <Search size={32} className="mx-auto mb-2 opacity-50" />
                <p>Nenhum registro encontrado para a busca atual.</p>
             </div>
          )}
        </div>
      </div>

       {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh]">
             <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                <h3 className="font-bold">
                  {activeTab === 'catequizandos' ? 'Cadastrar Catequizando' : 
                   activeTab === 'familias' ? 'Cadastrar Família' : 'Cadastrar Catequista'}
                </h3>
                <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
             </div>
             <form onSubmit={handleSave} className="p-6 space-y-4 overflow-y-auto">
                {renderModalContent()}
                <button 
                  type="submit"
                  className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors mt-4"
                >
                   Salvar Cadastro
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

