// Data Model based on Supabase Structure

export enum UserRole {
  COORDENADOR = 'Coordenador de Catequese',
  CATEQUISTA = 'Catequista',
  ADMIN = 'Administrador Paroquial',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  paroquia: string;
  avatar?: string;
}

export interface Diocese {
  id: string;
  nome: string;
  bispo: string;
}

export interface Paroquia {
  id: string;
  diocese_id: string;
  nome: string;
  endereco: string;
  telefone: string;
}

export interface Comunidade {
  id: string;
  paroquia_id: string;
  nome: string;
  padroeiro: string;
}

export interface EtapaCatequese {
  id: string;
  nome: string; // Ex: Eucaristia I, Crisma
}

export interface Turma {
  id: string;
  comunidade_id: string;
  etapa_id: string;
  etapa_nome?: string; // Helper for UI
  ano: number;
  faixa_etaria: string;
  dia_encontro: string;
  horario: string;
}

export interface Catequizando {
  id: string;
  turma_id: string;
  nome_completo: string;
  data_nascimento: string;
  nome_responsavel: string;
  telefone_responsavel: string;
  sacramentos: {
    batismo: boolean;
    eucaristia: boolean;
    crisma: boolean;
  };
  observacoes_pastorais: string;
  familia_id?: string;
}

export interface Familia {
  id: string;
  sobrenome: string; // Ex: Família Silva
  pai: string;
  mae: string;
  casados_igreja: boolean;
  endereco: string;
  telefone_principal: string;
  observacoes: string;
}

export interface Catequista {
  id: string;
  nome: string;
  email: string;
  telefone: string;
  comunidade_id: string;
  tempo_servico_anos: number;
}

export enum LiturgicalColor {
  GREEN = 'Tempo Comum',
  PURPLE = 'Advento/Quaresma',
  RED = 'Mártires/Pentecostes',
  WHITE = 'Solenidades'
}

export interface Encontro {
  id: string;
  turma_id: string;
  data: string;
  tema: string;
  cor_liturgica: LiturgicalColor;
  observacoes: string;
  concluido: boolean;
}

export interface Presenca {
  id: string;
  encontro_id: string;
  catequizando_id: string;
  status: 'P' | 'F' | 'J'; // Presente, Falta, Justificada
}

export interface MaterialApoio {
  id: string;
  titulo: string;
  descricao: string;
  tipo: 'PDF' | 'LINK' | 'VIDEO' | 'DOC';
  categoria: 'Formação' | 'Liturgia' | 'Dinâmicas' | 'Administrativo';
  url: string;
  data_adicao: string;
}

