              <p className="text-sm text-gray-500 text-center py-4">Nenhum aniversariante este mês.</p>
            )}
          </div>

          {/* Quick Notices */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
            <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
              <AlertCircle className="mr-2 text-church-600" size={20} />
              Avisos Pastorais
            </h3>
            <ul className="space-y-3">
              <li className="p-3 bg-yellow-50 text-yellow-800 rounded-lg text-sm border border-yellow-100">
                <strong>Reunião de Pais:</strong> Sábado, dia 20 às 15h no Salão Paroquial.
              </li>
              <li className="p-3 bg-blue-50 text-blue-800 rounded-lg text-sm border border-blue-100">
                <strong>Missa de Entrega:</strong> Lembrar os catequizandos de trazerem suas bíblias no próximo domingo.
              </li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Calendar, CheckCircle, Clock, FileText, ChevronRight, Plus, X, Users, Check, AlertCircle } from 'lucide-react';
import { useData } from '../contexts/DataContext';
import { Encontro, LiturgicalColor, Presenca } from '../types';

const MeetingManager: React.FC = () => {
  const { turmas, encontros, catequizandos, presencas, addEncontro, updatePresenca } = useData();

  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Form State
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        // Simple toggle for Roll Call Mode: Present (P) <-> Absent (F)
        // Justified (J) is usually set manually in detailed view, but here we toggle main states
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        // Create new as Absent if they were not there? No, usually clicking means they are here or toggling.
        // Let's assume clicking a name in Roll Call List marks them as Present (if no record) or toggles.
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null; // Return null if no record yet (pending)
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Encontros & Frequência</h2>
        <select 
          value={selectedTurma}
          onChange={(e) => {
            setSelectedTurma(e.target.value);
            setSelectedEncontro(null);
            setIsChamadaMode(false);
          }}
          className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-church-500 focus:border-church-500 block p-2.5"
        >
          {turmas.map(turma => (
            <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-4 bg-gray-50 border-b border-gray-200">
            <h3 className="font-semibold text-gray-700">Agenda da Turma</h3>
          </div>
          <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false); // Reset mode when switching meeting
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-colors flex justify-between items-center ${selectedEncontro === encontro.id ? 'bg-church-50 border-l-4 border-church-500' : ''}`}
              >
                <div>
                  <p className="font-medium text-gray-900">{encontro.tema}</p>
                  <div className="flex items-center text-xs text-gray-500 mt-1 space-x-2">
                    <span className="flex items-center"><Calendar size={12} className="mr-1"/> {new Date(encontro.data).toLocaleDateString()}</span>
                    {encontro.concluido && <span className="flex items-center text-green-600"><CheckCircle size={12} className="mr-1"/> Realizado</span>}
                  </div>
                </div>
                <ChevronRight size={16} className="text-gray-400" />
              </button>
            ))}
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full p-3 text-center text-sm text-church-600 font-medium hover:bg-church-50 transition-colors flex items-center justify-center"
            >
              <Plus size={16} className="mr-1"/> Agendar Novo Encontro
            </button>
          </div>
        </div>

        {/* Details / Attendance Area */}
        <div className="lg:col-span-2 space-y-6">
          {selectedEncontro && currentEncontroDetails ? (
            <div className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${isChamadaMode ? 'ring-2 ring-church-500 shadow-lg' : ''}`}>
               <div className={`p-6 border-b border-gray-200 flex justify-between items-center ${isChamadaMode ? 'bg-church-50' : ''}`}>
                  <div>
                    <h3 className="text-xl font-bold text-gray-900">{currentEncontroDetails.tema}</h3>
                    <p className="text-sm text-gray-500 flex items-center mt-1">
                      <Clock size={16} className="mr-1"/> 
                      {new Date(currentEncontroDetails.data).toLocaleDateString()} • {currentEncontroDetails.cor_liturgica}
                    </p>
                  </div>
                  <div className="flex space-x-2">
                     {!isChamadaMode ? (
                        <>
                            <button className="px-3 py-2 text-sm bg-white border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 flex items-center">
                                <FileText size={16} className="mr-2"/> Detalhes
                            </button>
                            <button 
                                onClick={() => setIsChamadaMode(true)}
                                className="px-4 py-2 text-sm bg-church-600 text-white rounded-lg hover:bg-church-700 flex items-center font-semibold shadow-sm animate-pulse"
                            >
                                <Users size={16} className="mr-2"/> Fazer Chamada
                            </button>
                        </>
                     ) : (
                        <button 
                            onClick={() => setIsChamadaMode(false)}
                            className="px-4 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center font-semibold"
                        >
                            <Check size={16} className="mr-2"/> Concluir Chamada
                        </button>
                     )}
                  </div>
               </div>

               <div className="p-6">
                 {isChamadaMode ? (
                     // ROLL CALL MODE INTERFACE
                     <div className="space-y-4">
                         <div className="bg-yellow-50 p-3 rounded-lg flex items-start text-sm text-yellow-800 border border-yellow-100 mb-4">
                            <AlertCircle size={16} className="mt-0.5 mr-2 shrink-0"/>
                            <p>Toque no nome do catequizando para alternar entre <strong>Presente</strong> e <strong>Falta</strong>.</p>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {activeCatequizandos.map(aluno => {
                                 const status = getStatus(aluno.id);
                                 // Default visual state for no record is "Pending/Absent looking" or just white
                                 const isPresent = status === 'P';
                                 const isAbsent = status === 'F';

                                 return (
                                     <button 
                                        key={aluno.id}
                                        onClick={() => togglePresenca(aluno.id)}
                                        className={`p-4 rounded-xl border-2 flex items-center justify-between transition-all duration-200 
                                            ${isPresent ? 'border-green-500 bg-green-50' : ''}
                                            ${isAbsent ? 'border-red-300 bg-red-50 opacity-70' : ''}
                                            ${!status ? 'border-gray-200 bg-white hover:border-church-300' : ''}
                                        `}
                                     >
                                         <div className="flex items-center">
                                             <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm mr-3 transition-colors
                                                 ${isPresent ? 'bg-green-200 text-green-800' : 'bg-gray-100 text-gray-500'}
                                             `}>
                                                 {aluno.nome_completo.charAt(0)}
                                             </div>
                                             <div className="text-left">
                                                 <p className={`font-bold ${isPresent ? 'text-green-900' : 'text-gray-900'}`}>{aluno.nome_completo}</p>
                                                 <p className="text-xs text-gray-500">{isPresent ? 'Presente' : isAbsent ? 'Ausente' : 'Toque para marcar'}</p>
                                             </div>
                                         </div>
                                         <div>
                                             {isPresent && <CheckCircle className="text-green-600" size={24} />}
                                         </div>
                                     </button>
                                 )
                             })}
                         </div>
                     </div>
                 ) : (
                     // VIEW MODE INTERFACE
                     <div className="space-y-3">
                        <div className="flex justify-between items-center mb-4">
                            <h4 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Resumo da Presença</h4>
                            <div className="flex space-x-4 text-xs">
                                <span className="flex items-center"><span className="w-3 h-3 rounded-full bg-green-500 mr-1"></span> Presente</span>
                                <span className="flex items-center"><span className="w-3 h-3 rounded-full bg-red-500 mr-1"></span> Falta</span>
                            </div>
                        </div>
                        {activeCatequizandos.length > 0 ? activeCatequizandos.map(aluno => {
                        const status = getStatus(aluno.id);
                        return (
                            <div key={aluno.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100">
                            <div className="flex items-center space-x-3">
                                <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-xs font-bold text-gray-600">
                                {aluno.nome_completo.charAt(0)}
                                </div>
                                <div>
                                <p className="font-medium text-gray-900">{aluno.nome_completo}</p>
                                </div>
                            </div>

                            <div className="flex items-center space-x-2">
                                <span className={`px-3 py-1 rounded-full text-xs font-bold
                                    ${status === 'P' ? 'bg-green-100 text-green-700' : ''}
                                    ${status === 'F' ? 'bg-red-100 text-red-700' : ''}
                                    ${status === 'J' ? 'bg-yellow-100 text-yellow-700' : ''}
                                    ${!status ? 'bg-gray-200 text-gray-500' : ''}
                                `}>
                                    {status === 'P' ? 'Presente' : status === 'F' ? 'Falta' : status === 'J' ? 'Justificada' : 'Pendente'}
                                </span>
                            </div>
                            </div>
                        );
                        }) : (
                            <p className="text-center text-gray-500 py-4">Nenhum catequizando nesta turma.</p>
                        )}
                    </div>
                 )}
               </div>
            </div>
          ) : (
            <div className="h-40 flex flex-col items-center justify-center bg-white rounded-xl border border-dashed border-gray-300 p-8 text-gray-400">
              <Calendar size={48} className="mb-4 text-gray-200" />
              <p className="text-lg font-medium">Selecione um encontro para iniciar a chamada</p>
            </div>
          )}

          {/* Liturgical Calendar Widget - Now here! */}
          <div className="bg-gradient-to-r from-green-700 to-green-600 rounded-xl p-6 text-white shadow-lg relative overflow-hidden mt-6">
            <div className="relative z-10">
              <div className="flex items-center space-x-2 mb-2">
                <span className="bg-white/20 px-2 py-1 rounded text-xs font-semibold uppercase tracking-wide">Liturgia de Hoje</span>
              </div>
              <h3 className="text-2xl font-bold mb-1">Tempo Comum</h3>
              <p className="text-green-100 text-sm max-w-lg">
                Estamos caminhando no tempo ordinário da igreja. A cor litúrgica é o Verde, simbolizando a esperança cristã.
              </p>
              <div className="mt-4 flex space-x-4">
                  <div className="bg-white/10 p-3 rounded-lg">
                      <p className="text-xs opacity-75 uppercase">Evangelho</p>
                      <p className="font-semibold">Mateus 5, 1-12</p>
                  </div>
                  <div className="bg-white/10 p-3 rounded-lg">
                      <p className="text-xs opacity-75 uppercase">Salmo</p>
                      <p className="font-semibold">Salmo 23</p>
                  </div>
              </div>
            </div>
            <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-white/10 w-48 h-48" />
          </div>
        </div>
      </div>

      {/* Modal Novo Encontro */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden">
             <div className="bg-church-600 p-4 flex justify-between items-center text-white">
                <h3 className="font-bold">Agendar Novo Encontro</h3>
                <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
             </div>
             <form onSubmit={handleSaveEncontro} className="p-6 space-y-4">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tema do Encontro</label>
                   <input 
                      type="text" 
                      required
                      value={newEncontro.tema}
                      onChange={e => setNewEncontro({...newEncontro, tema: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                      placeholder="Ex: Os Mandamentos"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
                   <input 
                      type="date" 
                      required
                      value={newEncontro.data}
                      onChange={e => setNewEncontro({...newEncontro, data: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Cor Litúrgica</label>
                   <select 
                      value={newEncontro.cor_liturgica}
                      onChange={e => setNewEncontro({...newEncontro, cor_liturgica: e.target.value as LiturgicalColor})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      {Object.values(LiturgicalColor).map(cor => (
                         <option key={cor} value={cor}>{cor}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Observações</label>
                   <textarea 
                      value={newEncontro.observacoes}
                      onChange={e => setNewEncontro({...newEncontro, observacoes: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none h-20"
                      placeholder="Material necessário, avisos, etc."
                   />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
                >
                   Salvar Agendamento
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MeetingManager;

