import React, { createContext, useContext, useState, ReactNode } from 'react';
import { 
  Catequizando, 
  Catequista, 
  Familia, 
  Encontro, 
  Presenca, 
  Turma, 
  Paroquia,
  MaterialApoio,
  Aviso,
  UserRole
} from '../types';
import { 
  MOCK_CATEQUIZANDOS, 
  MOCK_CATEQUISTAS, 
  MOCK_FAMILIAS, 
  MOCK_ENCONTROS, 
  MOCK_PRESENCAS,
  MOCK_TURMAS,
  MOCK_PAROQUIA,
  MOCK_MATERIAIS,
  MOCK_AVISOS
} from '../constants';

interface DataContextType {
  paroquia: Paroquia;
  turmas: Turma[];
  catequizandos: Catequizando[];
  familias: Familia[];
  catequistas: Catequista[];
  encontros: Encontro[];
  presencas: Presenca[];
  materiais: MaterialApoio[];
  avisos: Aviso[];

  // Actions
  addCatequizando: (data: Omit<Catequizando, 'id'>) => void;
  addFamilia: (data: Omit<Familia, 'id'>) => void;
  addCatequista: (data: Omit<Catequista, 'id'>) => void;
  addEncontro: (data: Omit<Encontro, 'id'>) => void;
  updatePresenca: (presenca: Presenca) => void;
  addMaterial: (data: Omit<MaterialApoio, 'id' | 'data_adicao'>) => void;
  addAviso: (data: Omit<Aviso, 'id' | 'data_publicacao'>) => void;
  removeAviso: (id: string) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [catequizandos, setCatequizandos] = useState<Catequizando[]>(MOCK_CATEQUIZANDOS);
  const [familias, setFamilias] = useState<Familia[]>(MOCK_FAMILIAS);
  const [catequistas, setCatequistas] = useState<Catequista[]>(MOCK_CATEQUISTAS);
  const [encontros, setEncontros] = useState<Encontro[]>(MOCK_ENCONTROS);
  const [presencas, setPresencas] = useState<Presenca[]>(MOCK_PRESENCAS);
  const [materiais, setMateriais] = useState<MaterialApoio[]>(MOCK_MATERIAIS);
  const [avisos, setAvisos] = useState<Aviso[]>(MOCK_AVISOS);

  // Static data for now, but could be dynamic later
  const turmas = MOCK_TURMAS;
  const paroquia = MOCK_PAROQUIA;

  const addCatequizando = (data: Omit<Catequizando, 'id'>) => {
    const newId = Date.now().toString();
    setCatequizandos([...catequizandos, { ...data, id: newId }]);
  };

  const addFamilia = (data: Omit<Familia, 'id'>) => {
    const newId = Date.now().toString();
    setFamilias([...familias, { ...data, id: newId }]);
  };

  const addCatequista = (data: Omit<Catequista, 'id'>) => {
    const newId = Date.now().toString();
    setCatequistas([...catequistas, { ...data, id: newId }]);
  };

  const addEncontro = (data: Omit<Encontro, 'id'>) => {
    const newId = Date.now().toString();
    setEncontros([...encontros, { ...data, id: newId }]);
  };

  const updatePresenca = (presenca: Presenca) => {
    setPresencas(prev => {
      const index = prev.findIndex(p => p.id === presenca.id);
      if (index >= 0) {
        const newPresencas = [...prev];
        newPresencas[index] = presenca;
        return newPresencas;
      } else {
        return [...prev, presenca];
      }
    });
  };

  const addMaterial = (data: Omit<MaterialApoio, 'id' | 'data_adicao'>) => {
      const newId = Date.now().toString();
      const newMaterial: MaterialApoio = {
          ...data,
          id: newId,
          data_adicao: new Date().toISOString().split('T')[0]
      };
      setMateriais([...materiais, newMaterial]);
  };

  const addAviso = (data: Omit<Aviso, 'id' | 'data_publicacao'>) => {
    const newId = Date.now().toString();
    const newAviso: Aviso = {
      ...data,
      id: newId,
      data_publicacao: new Date().toISOString().split('T')[0]
    };
    setAvisos([newAviso, ...avisos]); // Add to top
  };

  const removeAviso = (id: string) => {
    setAvisos(avisos.filter(a => a.id !== id));
  };

  return (
    <DataContext.Provider value={{
      paroquia,
      turmas,
      catequizandos,
      familias,
      catequistas,
      encontros,
      presencas,
      materiais,
      avisos,
      addCatequizando,
      addFamilia,
      addCatequista,
      addEncontro,
      updatePresenca,
      addMaterial,
      addAviso,
      removeAviso
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

