  const { turmas, encontros, catequizandos, presencas, addEncontro, updatePresenca } = useData();

  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Liturgy Preview State
  const [liturgyPreview, setLiturgyPreview] = useState<LiturgyInfo | null>(null);

  // Form State
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null;
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const date = e.target.value;

    // 1. Update basic form state
    const updatedEncontro = { ...newEncontro, data: date };

    // 2. Fetch Liturgical Details
    if (date) {
        const details = getLiturgicalDetails(date);
        setLiturgyPreview(details);

        // Auto-select the liturgical color
        updatedEncontro.cor_liturgica = details.cor;
    } else {
        setLiturgyPreview(null);
    }

    setNewEncontro(updatedEncontro);
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
    setLiturgyPreview(null);
  };

  // Helper to render color badge in Modal
  const getLiturgicalColorClass = (cor: LiturgicalColor) => {
      switch (cor) {
          case LiturgicalColor.GREEN: return 'bg-green-600';
          case LiturgicalColor.PURPLE: return 'bg-purple-700';
          case LiturgicalColor.RED: return 'bg-red-600';
          case LiturgicalColor.WHITE: return 'bg-yellow-500'; // Gold for white
          default: return 'bg-gray-500';
      }
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Encontros & Frequência</h2>
        <select 
          value={selectedTurma}
          onChange={(e) => {
            setSelectedTurma(e.target.value);
            setSelectedEncontro(null);
            setIsChamadaMode(false);
          }}
          className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-church-500 focus:border-church-500 block p-2.5"
        >
          {turmas.map(turma => (
            <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-4 bg-gray-50 border-b border-gray-200">
            <h3 className="font-semibold text-gray-700">Agenda da Turma</h3>
          </div>
          <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false); // Reset mode when switching meeting
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-colors flex justify-between items-center ${selectedEncontro === encontro.id ? 'bg-church-50 border-l-4 border-church-500' : ''}`}
              >
                <div>
                  <p className="font-medium text-gray-900">{encontro.tema}</p>
                  <div className="flex items-center text-xs text-gray-500 mt-1 space-x-2">
                    <span className="flex items-center"><Calendar size={12} className="mr-1"/> {new Date(encontro.data).toLocaleDateString()}</span>
                    {encontro.concluido && <span className="flex items-center text-green-600"><CheckCircle size={12} className="mr-1"/> Realizado</span>}
                  </div>
                </div>
                <ChevronRight size={16} className="text-gray-400" />
              </button>
            ))}
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full p-3 text-center text-sm text-church-600 font-medium hover:bg-church-50 transition-colors flex items-center justify-center"
            >
              <Plus size={16} className="mr-1"/> Agendar Novo Encontro
            </button>
          </div>
        </div>

        {/* Details / Attendance Area */}
        <div className="lg:col-span-2 space-y-6">
          {selectedEncontro && currentEncontroDetails ? (
            <div className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${isChamadaMode ? 'ring-2 ring-church-500 shadow-lg' : ''}`}>
               <div className={`p-6 border-b border-gray-200 flex justify-between items-center ${isChamadaMode ? 'bg-church-50' : ''}`}>
                  <div>
                    <h3 className="text-xl font-bold text-gray-900">{currentEncontroDetails.tema}</h3>
                    <p className="text-sm text-gray-500 flex items-center mt-1">
                      <Clock size={16} className="mr-1"/> 
                      {new Date(currentEncontroDetails.data).toLocaleDateString()} • {currentEncontroDetails.cor_liturgica}
                    </p>
                  </div>
                  <div className="flex space-x-2">
                     {!isChamadaMode ? (
                        <>
                            <button className="px-3 py-2 text-sm bg-white border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 flex items-center">
                                <FileText size={16} className="mr-2"/> Detalhes
                            </button>
                            <button 
                                onClick={() => setIsChamadaMode(true)}
                                className="px-4 py-2 text-sm bg-church-600 text-white rounded-lg hover:bg-church-700 flex items-center font-semibold shadow-sm animate-pulse"
                            >
                                <Users size={16} className="mr-2"/> Fazer Chamada
                            </button>
                        </>
                     ) : (
                        <button 
                            onClick={() => setIsChamadaMode(false)}
                            className="px-4 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center font-semibold"
                        >
                            <Check size={16} className="mr-2"/> Concluir Chamada
                        </button>
                     )}
                  </div>
               </div>

               <div className="p-6">
                 {isChamadaMode ? (
                     // ROLL CALL MODE INTERFACE
                     <div className="space-y-4">
                         <div className="bg-yellow-50 p-3 rounded-lg flex items-start text-sm text-yellow-800 border border-yellow-100 mb-4">
                            <AlertCircle size={16} className="mt-0.5 mr-2 shrink-0"/>
                            <p>Toque no nome do catequizando para alternar entre <strong>Presente</strong> e <strong>Falta</strong>.</p>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {activeCatequizandos.map(aluno => {
                                 const status = getStatus(aluno.id);
                                 const isPresent = status === 'P';
                                 const isAbsent = status === 'F';

                                 return (
                                     <button 
                                        key={aluno.id}
                                        onClick={() => togglePresenca(aluno.id)}
                                        className={`p-4 rounded-xl border-2 flex items-center justify-between transition-all duration-200 
                                            ${isPresent ? 'border-green-500 bg-green-50' : ''}
                                            ${isAbsent ? 'border-red-300 bg-red-50 opacity-70' : ''}
                                            ${!status ? 'border-gray-200 bg-white hover:border-church-300' : ''}
                                        `}
                                     >
                                         <div className="flex items-center">
                                             <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm mr-3 transition-colors
                                                 ${isPresent ? 'bg-green-200 text-green-800' : 'bg-gray-100 text-gray-500'}
                                             `}>
                                                 {aluno.nome_completo.charAt(0)}
                                             </div>
                                             <div className="text-left">
                                                 <p className={`font-bold ${isPresent ? 'text-green-900' : 'text-gray-900'}`}>{aluno.nome_completo}</p>
                                                 <p className="text-xs text-gray-500">{isPresent ? 'Presente' : isAbsent ? 'Ausente' : 'Toque para marcar'}</p>
                                             </div>
                                         </div>
                                         <div>
                                             {isPresent && <CheckCircle className="text-green-600" size={24} />}
                                         </div>
                                     </button>
                                 )
                             })}
                         </div>
                     </div>
                 ) : (
                     // VIEW MODE INTERFACE
                     <div className="space-y-3">
                        <div className="flex justify-between items-center mb-4">
                            <h4 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Resumo da Presença</h4>
                            <div className="flex space-x-4 text-xs">
                                <span className="flex items-center"><span className="w-3 h-3 rounded-full bg-green-500 mr-1"></span> Presente</span>
                                <span className="flex items-center"><span className="w-3 h-3 rounded-full bg-red-500 mr-1"></span> Falta</span>
                            </div>
                        </div>
                        {activeCatequizandos.length > 0 ? activeCatequizandos.map(aluno => {
                        const status = getStatus(aluno.id);
                        return (
                            <div key={aluno.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100">
                            <div className="flex items-center space-x-3">
                                <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-xs font-bold text-gray-600">
                                {aluno.nome_completo.charAt(0)}
                                </div>
                                <div>
                                <p className="font-medium text-gray-900">{aluno.nome_completo}</p>
                                </div>
                            </div>

                            <div className="flex items-center space-x-2">
                                <span className={`px-3 py-1 rounded-full text-xs font-bold
                                    ${status === 'P' ? 'bg-green-100 text-green-700' : ''}
                                    ${status === 'F' ? 'bg-red-100 text-red-700' : ''}
                                    ${status === 'J' ? 'bg-yellow-100 text-yellow-700' : ''}
                                    ${!status ? 'bg-gray-200 text-gray-500' : ''}
                                `}>
                                    {status === 'P' ? 'Presente' : status === 'F' ? 'Falta' : status === 'J' ? 'Justificada' : 'Pendente'}
                                </span>
                            </div>
                            </div>
                        );
                        }) : (
                            <p className="text-center text-gray-500 py-4">Nenhum catequizando nesta turma.</p>
                        )}
                    </div>
                 )}
               </div>
            </div>
          ) : (
            <div className="h-40 flex flex-col items-center justify-center bg-white rounded-xl border border-dashed border-gray-300 p-8 text-gray-400">
              <Calendar size={48} className="mb-4 text-gray-200" />
              <p className="text-lg font-medium">Selecione um encontro para iniciar a chamada</p>
            </div>
          )}

          {/* Liturgical Calendar Widget (Static Footer) */}
          <div className="bg-gradient-to-r from-green-700 to-green-600 rounded-xl p-6 text-white shadow-lg relative overflow-hidden mt-6">
            <div className="relative z-10">
              <div className="flex items-center space-x-2 mb-2">
                <span className="bg-white/20 px-2 py-1 rounded text-xs font-semibold uppercase tracking-wide">Liturgia de Hoje</span>
              </div>
              <h3 className="text-2xl font-bold mb-1">Tempo Comum</h3>
              <p className="text-green-100 text-sm max-w-lg">
                Consulte o calendário litúrgico completo ao agendar um novo encontro para ver a cor e leituras do dia.
              </p>
            </div>
            <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-white/10 w-48 h-48" />
          </div>
        </div>
      </div>

      {/* Modal Novo Encontro */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
             <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                <h3 className="font-bold">Agendar Novo Encontro</h3>
                <button onClick={() => { setIsModalOpen(false); setLiturgyPreview(null); }}><X size={20} /></button>
             </div>

             <form onSubmit={handleSaveEncontro} className="p-6 space-y-4 overflow-y-auto">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data do Encontro</label>
                   <input 
                      type="date" 
                      required
                      value={newEncontro.data}
                      onChange={handleDateChange}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   />
                </div>

                {/* Liturgical Info Card (Dynamic) */}
                {liturgyPreview && (
                    <div className={`p-4 rounded-lg border flex flex-col md:flex-row gap-4 animate-fade-in
                        ${liturgyPreview.cor === LiturgicalColor.GREEN ? 'bg-green-50 border-green-200' : ''}
                        ${liturgyPreview.cor === LiturgicalColor.PURPLE ? 'bg-purple-50 border-purple-200' : ''}
                        ${liturgyPreview.cor === LiturgicalColor.RED ? 'bg-red-50 border-red-200' : ''}
                        ${liturgyPreview.cor === LiturgicalColor.WHITE ? 'bg-yellow-50 border-yellow-200' : ''}
                    `}>
                        <div className={`w-12 h-12 rounded-full flex items-center justify-center shrink-0 text-white shadow-sm
                            ${getLiturgicalColorClass(liturgyPreview.cor)}
                        `}>
                            <BookOpen size={20} />
                        </div>
                        <div className="flex-1">
                            <div className="flex justify-between items-start">
                                <h4 className="font-bold text-gray-900">{liturgyPreview.santo_ou_solenidade}</h4>
                                <span className="text-xs font-bold uppercase tracking-wide opacity-75 px-2 py-0.5 rounded bg-white/50">
                                    {liturgyPreview.cor}
                                </span>
                            </div>
                            <p className="text-sm font-medium opacity-90 mt-1">{liturgyPreview.tempo}</p>
                            <div className="mt-2 text-xs opacity-75 space-y-1">
                                <p className="flex items-center"><Sparkles size={10} className="mr-1"/> {liturgyPreview.descricao}</p>
                                <p className="flex items-center"><BookOpen size={10} className="mr-1"/> {liturgyPreview.leituras}</p>
                            </div>
                        </div>
                    </div>
                )}

                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tema do Encontro</label>
                   <input 
                      type="text" 
                      required
                      value={newEncontro.tema}
                      onChange={e => setNewEncontro({...newEncontro, tema: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                      placeholder="Ex: Os Mandamentos"
                   />
                </div>

                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Cor Litúrgica (Sugerida)</label>
                   <select 
                      value={newEncontro.cor_liturgica}
                      onChange={e => setNewEncontro({...newEncontro, cor_liturgica: e.target.value as LiturgicalColor})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      {Object.values(LiturgicalColor).map(cor => (
                         <option key={cor} value={cor}>{cor}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Observações</label>
                   <textarea 
                      value={newEncontro.observacoes}
                      onChange={e => setNewEncontro({...newEncontro, observacoes: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none h-20"
                      placeholder="Material necessário, avisos, etc."
                   />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
                >
                   Salvar Agendamento
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MeetingManager;

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { 
  Catequizando, 
  Catequista, 
  Familia, 
  Encontro, 
  Presenca, 
  Turma, 
  Paroquia,
  MaterialApoio,
  Aviso,
  UserRole
} from '../types';
import { 
  MOCK_CATEQUIZANDOS, 
  MOCK_CATEQUISTAS, 
  MOCK_FAMILIAS, 
  MOCK_ENCONTROS, 
  MOCK_PRESENCAS,
  MOCK_TURMAS,
  MOCK_PAROQUIA,
  MOCK_MATERIAIS,
  MOCK_AVISOS
} from '../constants';

interface DataContextType {
  paroquia: Paroquia;
  turmas: Turma[];
  catequizandos: Catequizando[];
  familias: Familia[];
  catequistas: Catequista[];
  encontros: Encontro[];
  presencas: Presenca[];
  materiais: MaterialApoio[];
  avisos: Aviso[];

  // Actions
  addCatequizando: (data: Omit<Catequizando, 'id'>) => void;
  addFamilia: (data: Omit<Familia, 'id'>) => void;
  addCatequista: (data: Omit<Catequista, 'id'>) => void;
  addEncontro: (data: Omit<Encontro, 'id'>) => void;
  updateEncontro: (encontro: Encontro) => void; // New action
  updatePresenca: (presenca: Presenca) => void;
  addMaterial: (data: Omit<MaterialApoio, 'id' | 'data_adicao'>) => void;
  addAviso: (data: Omit<Aviso, 'id' | 'data_publicacao'>) => void;
  removeAviso: (id: string) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [catequizandos, setCatequizandos] = useState<Catequizando[]>(MOCK_CATEQUIZANDOS);
  const [familias, setFamilias] = useState<Familia[]>(MOCK_FAMILIAS);
  const [catequistas, setCatequistas] = useState<Catequista[]>(MOCK_CATEQUISTAS);
  const [encontros, setEncontros] = useState<Encontro[]>(MOCK_ENCONTROS);
  const [presencas, setPresencas] = useState<Presenca[]>(MOCK_PRESENCAS);
  const [materiais, setMateriais] = useState<MaterialApoio[]>(MOCK_MATERIAIS);
  const [avisos, setAvisos] = useState<Aviso[]>(MOCK_AVISOS);

  // Static data for now, but could be dynamic later
  const turmas = MOCK_TURMAS;
  const paroquia = MOCK_PAROQUIA;

  const addCatequizando = (data: Omit<Catequizando, 'id'>) => {
    const newId = Date.now().toString();
    setCatequizandos([...catequizandos, { ...data, id: newId }]);
  };

  const addFamilia = (data: Omit<Familia, 'id'>) => {
    const newId = Date.now().toString();
    setFamilias([...familias, { ...data, id: newId }]);
  };

  const addCatequista = (data: Omit<Catequista, 'id'>) => {
    const newId = Date.now().toString();
    setCatequistas([...catequistas, { ...data, id: newId }]);
  };

  const addEncontro = (data: Omit<Encontro, 'id'>) => {
    const newId = Date.now().toString();
    setEncontros([...encontros, { ...data, id: newId }]);
  };

  const updateEncontro = (updatedEncontro: Encontro) => {
    setEncontros(prev => prev.map(e => e.id === updatedEncontro.id ? updatedEncontro : e));
  };

  const updatePresenca = (presenca: Presenca) => {
    setPresencas(prev => {
      const index = prev.findIndex(p => p.id === presenca.id);
      if (index >= 0) {
        const newPresencas = [...prev];
        newPresencas[index] = presenca;
        return newPresencas;
      } else {
        return [...prev, presenca];
      }
    });
  };

  const addMaterial = (data: Omit<MaterialApoio, 'id' | 'data_adicao'>) => {
      const newId = Date.now().toString();
      const newMaterial: MaterialApoio = {
          ...data,
          id: newId,
          data_adicao: new Date().toISOString().split('T')[0]
      };
      setMateriais([...materiais, newMaterial]);
  };

  const addAviso = (data: Omit<Aviso, 'id' | 'data_publicacao'>) => {
    const newId = Date.now().toString();
    const newAviso: Aviso = {
      ...data,
      id: newId,
      data_publicacao: new Date().toISOString().split('T')[0]
    };
    setAvisos([newAviso, ...avisos]); // Add to top
  };

  const removeAviso = (id: string) => {
    setAvisos(avisos.filter(a => a.id !== id));
  };

  return (
    <DataContext.Provider value={{
      paroquia,
      turmas,
      catequizandos,
      familias,
      catequistas,
      encontros,
      presencas,
      materiais,
      avisos,
      addCatequizando,
      addFamilia,
      addCatequista,
      addEncontro,
      updateEncontro,
      updatePresenca,
      addMaterial,
      addAviso,
      removeAviso
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCatecheticalPlan = async (
  etapa: string,
  tempo: string,
  userPrompt: string
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Atue como um catequista católico experiente e fiel ao magistério.
      Crie um plano de encontro detalhado com a seguinte estrutura:
      1. Tema e Objetivo
      2. Acolhida e Oração Inicial
      3. Leitura Bíblica (indicar passagem apropriada)
      4. Desenvolvimento do Tema (Dinâmica ou Explicação)
      5. Atividade Prática
      6. Oração Final

      Contexto do Encontro:
      - Etapa Catequética: ${etapa}
      - Tempo Litúrgico: ${tempo}
      - Solicitação Específica: ${userPrompt}

      Utilize uma linguagem acolhedora e adequada à faixa etária da etapa informada.`,
      config: {
        systemInstruction: "Você é um assistente pastoral especializado em catequese católica.",
      },
    });

    return response.text || "Não foi possível gerar o plano neste momento.";
  } catch (error) {
    console.error("Erro ao gerar plano:", error);
    return "Ocorreu um erro ao comunicar com o assistente IA. Por favor, verifique a chave de API.";
  }
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCatecheticalPlan = async (
  etapa: string,
  tempo: string,
  userPrompt: string
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: `Atue como um catequista católico experiente e fiel ao magistério.
      Crie um plano de encontro detalhado com a seguinte estrutura:
      1. Tema e Objetivo
      2. Acolhida e Oração Inicial
      3. Leitura Bíblica (indicar passagem apropriada)
      4. Desenvolvimento do Tema (Dinâmica ou Explicação)
      5. Atividade Prática
      6. Oração Final

      Contexto do Encontro:
      - Etapa Catequética: ${etapa}
      - Tempo Litúrgico: ${tempo}
      - Solicitação Específica: ${userPrompt}

      Utilize uma linguagem acolhedora e adequada à faixa etária da etapa informada.`,
      config: {
        systemInstruction: "Você é um assistente pastoral especializado em catequese católica.",
      },
    });

    return response.text || "Não foi possível gerar o plano neste momento.";
  } catch (error) {
    console.error("Erro ao gerar plano:", error);
    return "Ocorreu um erro ao comunicar com o assistente IA. Por favor, verifique a chave de API.";
  }
};

export interface LiturgySuggestion {
  santo: string;
  cor: string;
  leituras: string;
  tema_sugerido: string;
  ideia_dinamica: string;
}

export const getLiturgicalSuggestions = async (date: string, etapaContext: string): Promise<LiturgySuggestion | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: `Para a data ${date} e uma turma de catequese da etapa '${etapaContext}', retorne um objeto JSON com:
      - santo: O Santo do dia ou Solenidade litúrgica católica.
      - cor: A cor litúrgica (Verde, Branco, Vermelho, Roxo ou Rosa).
      - leituras: As referências bíblicas da liturgia diária (1ª Leitura, Salmo, Evangelho).
      - tema_sugerido: Um tema curto para o encontro baseado na liturgia ou no santo.
      - ideia_dinamica: Uma sugestão muito breve (1 frase) de atividade prática.

      Responda APENAS o JSON.`,
      config: {
        responseMimeType: "application/json",
      },
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as LiturgySuggestion;
  } catch (error) {
    console.error("Erro ao buscar sugestão litúrgica:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { Calendar, CheckCircle, Clock, FileText, ChevronRight, Plus, X, Users, Check, AlertCircle, BookOpen, Sparkles, Loader2, Save } from 'lucide-react';
import { useData } from '../contexts/DataContext';
import { Encontro, LiturgicalColor, Presenca } from '../types';
import { getLiturgicalSuggestions, LiturgySuggestion } from '../services/geminiService';

const MeetingManager: React.FC = () => {
  const { turmas, encontros, catequizandos, presencas, addEncontro, updatePresenca, updateEncontro } = useData();

  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // States for Meeting Details Edit
  const [editingObservation, setEditingObservation] = useState('');
  const [isEditing, setIsEditing] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Liturgy Preview State (AI)
  const [aiSuggestion, setAiSuggestion] = useState<LiturgySuggestion | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Form State
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);
  const activeTurmaName = turmas.find(t => t.id === selectedTurma)?.etapa_nome || 'Turma';

  // Update local state when meeting selection changes
  React.useEffect(() => {
    if (currentEncontroDetails) {
      setEditingObservation(currentEncontroDetails.observacoes || '');
    }
  }, [currentEncontroDetails]);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null;
  };

  const handleConsultAi = async () => {
    if (!newEncontro.data) return;
    setIsLoadingAi(true);
    setAiSuggestion(null);

    const suggestion = await getLiturgicalSuggestions(newEncontro.data, activeTurmaName);

    if (suggestion) {
        setAiSuggestion(suggestion);
        // Auto-map color approximate
        let mapColor = LiturgicalColor.GREEN;
        const sColor = suggestion.cor.toLowerCase();
        if (sColor.includes('roxo') || sColor.includes('lilás')) mapColor = LiturgicalColor.PURPLE;
        else if (sColor.includes('vermelho')) mapColor = LiturgicalColor.RED;
        else if (sColor.includes('branco') || sColor.includes('dourado') || sColor.includes('amarelo')) mapColor = LiturgicalColor.WHITE;

        setNewEncontro(prev => ({
            ...prev,
            cor_liturgica: mapColor,
            // Don't auto-fill theme yet, let user choose to apply
        }));
    }
    setIsLoadingAi(false);
  };

  const applyAiSuggestion = () => {
    if (!aiSuggestion) return;
    setNewEncontro(prev => ({
        ...prev,
        tema: aiSuggestion.tema_sugerido,
        observacoes: `Leituras: ${aiSuggestion.leituras}\nDinâmica: ${aiSuggestion.ideia_dinamica}`
    }));
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
    setAiSuggestion(null);
  };

  const handleUpdateDetails = () => {
    if (currentEncontroDetails) {
        updateEncontro({
            ...currentEncontroDetails,
            observacoes: editingObservation
        });
        setIsEditing(false);
    }
  };

  const toggleConcluido = () => {
      if (currentEncontroDetails) {
          updateEncontro({
              ...currentEncontroDetails,
              concluido: !currentEncontroDetails.concluido
          });
      }
  };

  // Helper to render color badge in Modal
  const getLiturgicalColorClass = (cor: LiturgicalColor) => {
      switch (cor) {
          case LiturgicalColor.GREEN: return 'bg-green-600';
          case LiturgicalColor.PURPLE: return 'bg-purple-700';
          case LiturgicalColor.RED: return 'bg-red-600';
          case LiturgicalColor.WHITE: return 'bg-yellow-500'; // Gold for white
          default: return 'bg-gray-500';
      }
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Encontros & Frequência</h2>
        <select 
          value={selectedTurma}
          onChange={(e) => {
            setSelectedTurma(e.target.value);
            setSelectedEncontro(null);
            setIsChamadaMode(false);
          }}
          className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-church-500 focus:border-church-500 block p-2.5"
        >
          {turmas.map(turma => (
            <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-4 bg-gray-50 border-b border-gray-200">
            <h3 className="font-semibold text-gray-700">Agenda da Turma</h3>
          </div>
          <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false);
                    setIsEditing(false);
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-colors flex justify-between items-center ${selectedEncontro === encontro.id ? 'bg-church-50 border-l-4 border-church-500' : ''}`}
              >
                <div>
                  <p className="font-medium text-gray-900">{encontro.tema}</p>
                  <div className="flex items-center text-xs text-gray-500 mt-1 space-x-2">
                    <span className="flex items-center"><Calendar size={12} className="mr-1"/> {new Date(encontro.data).toLocaleDateString()}</span>
                    {encontro.concluido && <span className="flex items-center text-green-600"><CheckCircle size={12} className="mr-1"/> Realizado</span>}
                  </div>
                </div>
                <ChevronRight size={16} className="text-gray-400" />
              </button>
            ))}
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full p-3 text-center text-sm text-church-600 font-medium hover:bg-church-50 transition-colors flex items-center justify-center"
            >
              <Plus size={16} className="mr-1"/> Agendar Novo Encontro
            </button>
          </div>
        </div>

        {/* Details / Attendance Area */}
        <div className="lg:col-span-2 space-y-6">
          {selectedEncontro && currentEncontroDetails ? (
            <div className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${isChamadaMode ? 'ring-2 ring-church-500 shadow-lg' : ''}`}>
               <div className={`p-6 border-b border-gray-200 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 ${isChamadaMode ? 'bg-church-50' : ''}`}>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
