        const primaryPhone = primaryResponsavel ? primaryResponsavel.telefone : '';
        const primaryName = primaryResponsavel ? primaryResponsavel.nome : 'Responsável';

        // Add IDs to responsibles
        const responsaveisWithIds = responsaveisList.map((r, idx) => ({
            ...r,
            id: `resp_${Date.now()}_${idx}`
        }));

