        addFamilia({
            sobrenome: `Família de ${studentForm.nome_completo.split(' ')[0]}`,
            responsaveis: responsaveisWithIds,
            endereco: familyForm.endereco,
            telefone_principal: primaryPhone,
            observacoes: familyForm.observacoes_familia
        });

        // Save Student
        addCatequizando({
            nome_completo: studentForm.nome_completo,
