                eucaristia: studentForm.eucaristia,
                crisma: studentForm.crisma
            },
            observacoes_pastorais: studentForm.observacoes_pastorais
        });

        // Reset form
        setStudentForm({
             nome_completo: '', data_nascimento: '', telefone: '', turma_id: turmas[0]?.id || '', 
             batismo: false, eucaristia: false, crisma: false, observacoes_pastorais: ''
        });
        setFamilyForm({ endereco: '', observacoes_familia: '' });
        setResponsaveisList([]);

