import { getLiturgicalSuggestions, LiturgySuggestion } from '../services/geminiService';

const MeetingManager: React.FC = () => {
  const { turmas, encontros, catequizandos, presencas, addEncontro, updatePresenca, updateEncontro, paroquia } = useData();

  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // States for Meeting Details Edit
  const [editingObservation, setEditingObservation] = useState('');
  const [isEditing, setIsEditing] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Liturgy Preview State (AI)
  const [aiSuggestion, setAiSuggestion] = useState<LiturgySuggestion | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Form State
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);
  const activeTurmaName = turmas.find(t => t.id === selectedTurma)?.etapa_nome || 'Turma';
  const activeTurmaObj = turmas.find(t => t.id === selectedTurma);

  // Update local state when meeting selection changes
  React.useEffect(() => {
    if (currentEncontroDetails) {
      setEditingObservation(currentEncontroDetails.observacoes || '');
    }
  }, [currentEncontroDetails]);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null;
  };

  // --- PRINT FUNCTIONS ---

  const printStyles = `
    <style>
      body { font-family: 'Inter', sans-serif; padding: 40px; color: #1a1a1a; }
      .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; }
      .header h1 { font-size: 18px; font-weight: bold; margin: 0; text-transform: uppercase; }
      .header h2 { font-size: 14px; font-weight: normal; margin: 5px 0 0; color: #666; }
      .meta { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 30px; font-size: 14px; }
      .section-title { font-size: 16px; font-weight: bold; margin-bottom: 10px; color: #2563eb; border-left: 4px solid #2563eb; padding-left: 10px; }
      .content-box { border: 1px solid #e5e7eb; padding: 15px; border-radius: 8px; margin-bottom: 20px; font-size: 14px; white-space: pre-wrap; }
      table { width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 12px; }
      th, td { border: 1px solid #e5e7eb; padding: 8px 12px; text-align: left; }
      th { background-color: #f9fafb; font-weight: 600; text-transform: uppercase; font-size: 10px; }
      .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #9ca3af; border-top: 1px solid #e5e7eb; padding-top: 10px; }
      @media print { button { display: none; } body { padding: 0; } }
    </style>
  `;

  const handlePrintPauta = () => {
    if (!currentEncontroDetails) return;

    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    const html = `
      <html>
        <head><title>Pauta do Encontro - ${currentEncontroDetails.tema}</title>${printStyles}</head>
        <body>
          <div class="header">
            <h1>${paroquia.nome}</h1>
            <h2>Planejamento Catequético</h2>
          </div>

          <div class="meta">
            <div><strong>Turma:</strong> ${activeTurmaName}</div>
            <div><strong>Data:</strong> ${new Date(currentEncontroDetails.data).toLocaleDateString()}</div>
            <div><strong>Tema:</strong> ${currentEncontroDetails.tema}</div>
            <div><strong>Cor Litúrgica:</strong> ${currentEncontroDetails.cor_liturgica}</div>
          </div>

          <h3 class="section-title">Planejamento e Observações</h3>
          <div class="content-box">
            ${currentEncontroDetails.observacoes || 'Nenhuma observação registrada.'}
          </div>

          <h3 class="section-title">Anotações do Catequista</h3>
          <div class="content-box" style="height: 200px; border-style: dashed;">
            <!-- Espaço para anotação manual -->
          </div>

          <div class="footer">Gerado pelo sistema Lumen Fidei - ${new Date().toLocaleDateString()}</div>
          <script>window.print();</script>
        </body>
      </html>
    `;

    win.document.write(html);
    win.document.close();
  };

  const handlePrintChamada = () => {
    if (!currentEncontroDetails) return;

    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    const html = `
      <html>
        <head><title>Lista de Presença - ${new Date(currentEncontroDetails.data).toLocaleDateString()}</title>${printStyles}</head>
        <body>
          <div class="header">
            <h1>${paroquia.nome}</h1>
            <h2>Controle de Frequência</h2>
          </div>

          <div class="meta">
             <div><strong>Turma:</strong> ${activeTurmaName}</div>
             <div><strong>Encontro:</strong> ${currentEncontroDetails.tema}</div>
             <div><strong>Data:</strong> ${new Date(currentEncontroDetails.data).toLocaleDateString()}</div>
          </div>

          <table>
            <thead>
              <tr>
                <th style="width: 5%">#</th>
                <th style="width: 50%">Catequizando</th>
                <th style="width: 15%">Status</th>
                <th style="width: 30%">Assinatura / Observação</th>
              </tr>
            </thead>
            <tbody>
              ${activeCatequizandos.map((aluno, index) => {
                const status = getStatus(aluno.id);
                const statusText = status === 'P' ? 'Presente' : status === 'F' ? 'Falta' : 'Justificada';
                return `
                  <tr>
                    <td>${index + 1}</td>
                    <td>${aluno.nome_completo}</td>
                    <td>${status ? statusText : '___________'}</td>
                    <td></td>
                  </tr>
                `;
              }).join('')}
            </tbody>
          </table>

          <div class="meta" style="margin-top: 40px;">
             <div>__________________________________________<br>Assinatura do Catequista</div>
             <div>__________________________________________<br>Visto da Coordenação</div>
          </div>

          <div class="footer">Gerado pelo sistema Lumen Fidei - ${new Date().toLocaleDateString()}</div>
          <script>window.print();</script>
        </body>
      </html>
    `;

    win.document.write(html);
    win.document.close();
  };

  // --- END PRINT FUNCTIONS ---

  const handleConsultAi = async () => {
    if (!newEncontro.data) return;
    setIsLoadingAi(true);
    setAiSuggestion(null);

    const suggestion = await getLiturgicalSuggestions(newEncontro.data, activeTurmaName);

    if (suggestion) {
        setAiSuggestion(suggestion);
        // Auto-map color approximate
        let mapColor = LiturgicalColor.GREEN;
        const sColor = suggestion.cor.toLowerCase();
        if (sColor.includes('roxo') || sColor.includes('lilás')) mapColor = LiturgicalColor.PURPLE;
        else if (sColor.includes('vermelho')) mapColor = LiturgicalColor.RED;
        else if (sColor.includes('branco') || sColor.includes('dourado') || sColor.includes('amarelo')) mapColor = LiturgicalColor.WHITE;

        setNewEncontro(prev => ({
            ...prev,
            cor_liturgica: mapColor,
            // Don't auto-fill theme yet, let user choose to apply
        }));
    }
    setIsLoadingAi(false);
  };

  const applyAiSuggestion = () => {
    if (!aiSuggestion) return;
    setNewEncontro(prev => ({
        ...prev,
        tema: aiSuggestion.tema_sugerido,
        observacoes: `Leituras: ${aiSuggestion.leituras}\nDinâmica: ${aiSuggestion.ideia_dinamica}`
    }));
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
    setAiSuggestion(null);
  };

  const handleUpdateDetails = () => {
    if (currentEncontroDetails) {
        updateEncontro({
            ...currentEncontroDetails,
            observacoes: editingObservation
        });
        setIsEditing(false);
    }
  };

  const toggleConcluido = () => {
      if (currentEncontroDetails) {
          updateEncontro({
              ...currentEncontroDetails,
              concluido: !currentEncontroDetails.concluido
          });
      }
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Encontros & Frequência</h2>
        <select 
          value={selectedTurma}
          onChange={(e) => {
            setSelectedTurma(e.target.value);
            setSelectedEncontro(null);
            setIsChamadaMode(false);
          }}
          className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-church-500 focus:border-church-500 block p-2.5"
        >
          {turmas.map(turma => (
            <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-4 bg-gray-50 border-b border-gray-200">
            <h3 className="font-semibold text-gray-700">Agenda da Turma</h3>
          </div>
          <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false);
                    setIsEditing(false);
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-colors flex justify-between items-center ${selectedEncontro === encontro.id ? 'bg-church-50 border-l-4 border-church-500' : ''}`}
              >
                <div>
                  <p className="font-medium text-gray-900">{encontro.tema}</p>
                  <div className="flex items-center text-xs text-gray-500 mt-1 space-x-2">
                    <span className="flex items-center"><Calendar size={12} className="mr-1"/> {new Date(encontro.data).toLocaleDateString()}</span>
                    {encontro.concluido && <span className="flex items-center text-green-600"><CheckCircle size={12} className="mr-1"/> Realizado</span>}
                  </div>
                </div>
                <ChevronRight size={16} className="text-gray-400" />
              </button>
            ))}
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full p-3 text-center text-sm text-church-600 font-medium hover:bg-church-50 transition-colors flex items-center justify-center"
            >
              <Plus size={16} className="mr-1"/> Agendar Novo Encontro
            </button>
          </div>
        </div>

        {/* Details / Attendance Area */}
        <div className="lg:col-span-2 space-y-6">
          {selectedEncontro && currentEncontroDetails ? (
            <div className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${isChamadaMode ? 'ring-2 ring-church-500 shadow-lg' : ''}`}>
               <div className={`p-6 border-b border-gray-200 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 ${isChamadaMode ? 'bg-church-50' : ''}`}>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                         <h3 className="text-xl font-bold text-gray-900">{currentEncontroDetails.tema}</h3>
                         {currentEncontroDetails.concluido && (
                             <span className="px-2 py-0.5 rounded-full bg-green-100 text-green-800 text-xs font-bold flex items-center">
                                 <Check size={12} className="mr-1"/> Realizado
                             </span>
                         )}
                    </div>
                    <p className="text-sm text-gray-500 flex items-center mt-1">
                      <Clock size={16} className="mr-1"/> 
                      {new Date(currentEncontroDetails.data).toLocaleDateString()} • {currentEncontroDetails.cor_liturgica}
                    </p>
                  </div>
                  <div className="flex space-x-2">
                     {!isChamadaMode ? (
                        <>
                            <button 
                                onClick={handlePrintPauta}
                                className="px-3 py-2 text-sm bg-gray-100 text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-200 flex items-center transition-colors"
                                title="Imprimir Pauta do Encontro"
                            >
                                <Printer size={16} />
                            </button>
                            <button 
                                onClick={toggleConcluido}
                                className={`px-3 py-2 text-sm border rounded-lg flex items-center transition-colors
                                    ${currentEncontroDetails.concluido 
                                        ? 'bg-green-50 text-green-700 border-green-200 hover:bg-green-100' 
                                        : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                                    }`}
                            >
                                <CheckCircle size={16} className="mr-2"/> 
                                {currentEncontroDetails.concluido ? 'Concluído' : 'Marcar Concluído'}
                            </button>
                            <button 
                                onClick={() => setIsChamadaMode(true)}
                                className="px-4 py-2 text-sm bg-church-600 text-white rounded-lg hover:bg-church-700 flex items-center font-semibold shadow-sm animate-pulse"
                            >
                                <Users size={16} className="mr-2"/> Chamada
                            </button>
                        </>
                     ) : (
                        <>
                            <button 
                                onClick={handlePrintChamada}
                                className="px-3 py-2 text-sm bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center font-semibold"
                                title="Imprimir Lista de Chamada"
                            >
                                <Printer size={16} className="mr-2"/> Imprimir Lista
                            </button>
                            <button 
                                onClick={() => setIsChamadaMode(false)}
                                className="px-4 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center font-semibold"
                            >
                                <Check size={16} className="mr-2"/> Salvar Chamada
                            </button>
                        </>
                     )}
                  </div>
               </div>

               <div className="p-6">
                 {isChamadaMode ? (
                     // ROLL CALL MODE INTERFACE
                     <div className="space-y-4">
                         <div className="bg-yellow-50 p-3 rounded-lg flex items-start text-sm text-yellow-800 border border-yellow-100 mb-4">
                            <AlertCircle size={16} className="mt-0.5 mr-2 shrink-0"/>
                            <p>Toque no nome do catequizando para alternar entre <strong>Presente</strong> e <strong>Falta</strong>.</p>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {activeCatequizandos.map(aluno => {
                                 const status = getStatus(aluno.id);
                                 const isPresent = status === 'P';
                                 const isAbsent = status === 'F';

                                 return (
                                     <button 
                                        key={aluno.id}
                                        onClick={() => togglePresenca(aluno.id)}
                                        className={`p-4 rounded-xl border-2 flex items-center justify-between transition-all duration-200 
                                            ${isPresent ? 'border-green-500 bg-green-50' : ''}
                                            ${isAbsent ? 'border-red-300 bg-red-50 opacity-70' : ''}
                                            ${!status ? 'border-gray-200 bg-white hover:border-church-300' : ''}
                                        `}
                                     >
                                         <div className="flex items-center">
                                             <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm mr-3 transition-colors
                                                 ${isPresent ? 'bg-green-200 text-green-800' : 'bg-gray-100 text-gray-500'}
                                             `}>
                                                 {aluno.nome_completo.charAt(0)}
                                             </div>
                                             <div className="text-left">
                                                 <p className={`font-bold ${isPresent ? 'text-green-900' : 'text-gray-900'}`}>{aluno.nome_completo}</p>
                                                 <p className="text-xs text-gray-500">{isPresent ? 'Presente' : isAbsent ? 'Ausente' : 'Toque para marcar'}</p>
                                             </div>
                                         </div>
                                         <div>
                                             {isPresent && <CheckCircle className="text-green-600" size={24} />}
                                         </div>
                                     </button>
                                 )
                             })}
                         </div>
                     </div>
                 ) : (
                     // VIEW MODE & OBSERVATIONS
                     <div className="space-y-6">
                        {/* Attendance Summary */}
                        <div className="bg-gray-50 rounded-lg p-4 border border-gray-100">
                             <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Frequência</h4>
                             {activeCatequizandos.length > 0 ? (
                                <div className="flex flex-wrap gap-2">
                                    {activeCatequizandos.map(aluno => {
                                        const status = getStatus(aluno.id);
                                        return (
                                            <div key={aluno.id} className={`text-xs px-2 py-1 rounded border flex items-center
                                                ${status === 'P' ? 'bg-green-100 border-green-200 text-green-700' : ''}
                                                ${status === 'F' ? 'bg-red-100 border-red-200 text-red-700' : ''}
                                                ${!status ? 'bg-white border-gray-200 text-gray-500' : ''}
                                            `}>
                                                <div className={`w-2 h-2 rounded-full mr-2 ${status === 'P' ? 'bg-green-500' : status === 'F' ? 'bg-red-500' : 'bg-gray-300'}`}></div>
                                                {aluno.nome_completo.split(' ')[0]}
                                            </div>
                                        )
                                    })}
                                </div>
                             ) : <p className="text-sm text-gray-500">Sem alunos.</p>}
                        </div>

                        {/* Observations / Log */}
                        <div>
                             <div className="flex justify-between items-center mb-2">
                                 <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Observações / Planejamento</h4>
                                 {!isEditing && (
                                     <button onClick={() => setIsEditing(true)} className="text-xs text-church-600 font-medium hover:underline">
                                         Editar
                                     </button>
                                 )}
                             </div>

                             {isEditing ? (
                                 <div className="space-y-2">
                                     <textarea 
                                        className="w-full border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-church-500 outline-none h-32"
                                        value={editingObservation}
                                        onChange={(e) => setEditingObservation(e.target.value)}
                                        placeholder="Registre aqui como foi o encontro ou detalhes do planejamento..."
                                     />
                                     <div className="flex justify-end space-x-2">
                                         <button 
                                            onClick={() => { setIsEditing(false); setEditingObservation(currentEncontroDetails.observacoes || ''); }}
                                            className="px-3 py-1.5 text-sm text-gray-600 hover:bg-gray-100 rounded"
                                         >
                                             Cancelar
                                         </button>
                                         <button 
                                            onClick={handleUpdateDetails}
                                            className="px-3 py-1.5 text-sm bg-church-600 text-white rounded hover:bg-church-700 flex items-center"
                                         >
                                             <Save size={14} className="mr-1"/> Salvar
                                         </button>
                                     </div>
                                 </div>
                             ) : (
                                 <div className="bg-white border border-gray-200 rounded-lg p-4 text-sm text-gray-700 min-h-[80px] whitespace-pre-wrap">
                                     {currentEncontroDetails.observacoes || <span className="text-gray-400 italic">Nenhuma observação registrada.</span>}
                                 </div>
                             )}
                        </div>
                    </div>
                 )}
               </div>
            </div>
          ) : (
            <div className="h-40 flex flex-col items-center justify-center bg-white rounded-xl border border-dashed border-gray-300 p-8 text-gray-400">
              <Calendar size={48} className="mb-4 text-gray-200" />
              <p className="text-lg font-medium">Selecione um encontro para iniciar a chamada</p>
            </div>
          )}

          {/* Liturgical Calendar Widget (Static Footer) */}
          <div className="bg-gradient-to-r from-green-700 to-green-600 rounded-xl p-6 text-white shadow-lg relative overflow-hidden mt-6">
            <div className="relative z-10">
              <div className="flex items-center space-x-2 mb-2">
                <span className="bg-white/20 px-2 py-1 rounded text-xs font-semibold uppercase tracking-wide">Liturgia</span>
              </div>
              <h3 className="text-2xl font-bold mb-1">Ano Litúrgico</h3>
              <p className="text-green-100 text-sm max-w-lg">
                Utilize a IA Pastoral ao agendar novos encontros para alinhar sua catequese com a liturgia da Igreja.
              </p>
            </div>
            <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-white/10 w-48 h-48" />
          </div>
        </div>
      </div>

      {/* Modal Novo Encontro */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
             <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                <h3 className="font-bold">Agendar Novo Encontro</h3>
                <button onClick={() => { setIsModalOpen(false); setAiSuggestion(null); }}><X size={20} /></button>
             </div>

             <form onSubmit={handleSaveEncontro} className="p-6 space-y-4 overflow-y-auto">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data do Encontro</label>
                   <div className="flex gap-2">
                       <input 
                          type="date" 
                          required
                          value={newEncontro.data}
                          onChange={e => setNewEncontro({...newEncontro, data: e.target.value})}
                          className="flex-1 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                       />
                       <button
                          type="button"
                          onClick={handleConsultAi}
                          disabled={!newEncontro.data || isLoadingAi}
                          className="bg-purple-100 text-purple-700 px-3 py-2 rounded-lg font-semibold text-sm hover:bg-purple-200 transition-colors flex items-center disabled:opacity-50"
                          title="Consultar Santo, Cor e Ideias para a data"
                       >
                           {isLoadingAi ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} className="mr-2"/>}
                           IA Pastoral
                       </button>
                   </div>
                   <p className="text-xs text-gray-500 mt-1">Selecione a data e clique na IA para sugestões.</p>
                </div>

                {/* Liturgical Info Card (AI) */}
                {aiSuggestion && (
                    <div className="p-4 rounded-lg border bg-gradient-to-br from-indigo-50 to-white border-indigo-200 animate-fade-in relative group">
                        <div className="absolute top-2 right-2">
                             <button 
                                type="button" 
                                onClick={applyAiSuggestion} 
                                className="text-xs bg-indigo-600 text-white px-2 py-1 rounded shadow hover:bg-indigo-700"
                             >
                                 Usar Sugestão
                             </button>
                        </div>
