                            <p><span className="font-semibold text-gray-700">Tema:</span> {aiSuggestion.tema_sugerido}</p>
                            <div className="text-xs bg-white/50 p-2 rounded border border-indigo-100 mt-2">
                                <span className="font-semibold text-gray-700 block mb-1">Ideia Dinâmica:</span>
