import React, { useState, useEffect } from 'react';
import { Calendar, CheckCircle, Clock, FileText, ChevronRight, Plus, X, Users, Check, AlertCircle, BookOpen, Sparkles, Loader2, Save, Printer, Edit3 } from 'lucide-react';
