      .info-item strong { display: block; color: #4b5563; font-size: 11px; text-transform: uppercase; margin-bottom: 2px; }
      .info-item span { color: #111827; font-weight: 500; font-size: 14px; }

      .section-title { 
        font-family: 'Merriweather', serif;
        font-size: 16px; 
        font-weight: bold; 
        margin-top: 25px; 
        margin-bottom: 15px; 
