  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // States for Meeting Details Edit (Full Object)
  const [editingValues, setEditingValues] = useState<Partial<Encontro>>({});
  const [isEditing, setIsEditing] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Liturgy Preview State (AI)
  const [aiSuggestion, setAiSuggestion] = useState<LiturgySuggestion | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Custom Script Generation State
  const [customPrompt, setCustomPrompt] = useState('');
  const [isGeneratingScript, setIsGeneratingScript] = useState(false);

  // Form State for New Meeting
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);
  const activeTurmaName = turmas.find(t => t.id === selectedTurma)?.etapa_nome || 'Turma';
  const activeTurmaObj = turmas.find(t => t.id === selectedTurma);

  // Sync editing state when selection changes
  useEffect(() => {
    if (currentEncontroDetails) {
      setEditingValues({
        tema: currentEncontroDetails.tema,
        data: currentEncontroDetails.data,
        cor_liturgica: currentEncontroDetails.cor_liturgica,
        observacoes: currentEncontroDetails.observacoes
      });
      setIsEditing(false);
    }
  }, [currentEncontroDetails]);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null;
  };

  // --- PRINT FUNCTIONS ---

  const printStyles = `
    <style>
      @import url('https://fonts.googleapis.com/css2?family=Merriweather:wght@300;400;700&family=Roboto:wght@300;400;500&display=swap');
      body { font-family: 'Roboto', sans-serif; padding: 40px; color: #1a1a1a; line-height: 1.5; }
      .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; }
      .header h1 { font-family: 'Merriweather', serif; font-size: 20px; font-weight: bold; margin: 0; text-transform: uppercase; color: #1e3a8a; }
      .header h2 { font-size: 14px; font-weight: normal; margin: 5px 0 0; color: #666; letter-spacing: 1px; }

      .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; background: #f9fafb; padding: 15px; border-radius: 8px; border: 1px solid #e5e7eb; margin-bottom: 30px; font-size: 13px; }
      .info-item strong { display: block; color: #4b5563; font-size: 11px; text-transform: uppercase; margin-bottom: 2px; }
      .info-item span { color: #111827; font-weight: 500; font-size: 14px; }

      .section-title { 
        font-family: 'Merriweather', serif;
        font-size: 16px; 
        font-weight: bold; 
        margin-top: 25px; 
        margin-bottom: 15px; 
        color: #1e3a8a; 
        border-bottom: 1px solid #bfdbfe; 
        padding-bottom: 5px;
        display: flex;
        align-items: center;
      }

      .content-box { 
        font-family: 'Merriweather', serif;
        font-size: 14px; 
        white-space: pre-wrap; 
        text-align: justify;
        color: #374151;
      }

      /* Chamada Table Styles */
      table { width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 12px; }
      th, td { border: 1px solid #e5e7eb; padding: 8px 12px; text-align: left; }
      th { background-color: #f3f4f6; font-weight: 600; text-transform: uppercase; font-size: 10px; color: #374151; }

      .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #9ca3af; border-top: 1px solid #e5e7eb; padding-top: 10px; }

      @media print { 
        button { display: none; } 
        body { padding: 0; margin: 2cm; }
        .page-break { page-break-before: always; }
      }
    </style>
  `;

  const handlePrintPauta = () => {
    if (!currentEncontroDetails) return;

    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    // Use edited values if valid, otherwise saved values
    const tema = editingValues.tema || currentEncontroDetails.tema;
    const data = editingValues.data || currentEncontroDetails.data;
    const cor = editingValues.cor_liturgica || currentEncontroDetails.cor_liturgica;
    const obs = editingValues.observacoes || currentEncontroDetails.observacoes || '';

    const html = `
      <html>
        <head><title>Plano de Encontro - ${tema}</title>${printStyles}</head>
        <body>
          <div class="header">
            <h1>${paroquia.nome}</h1>
            <h2>Plano de Encontro Catequético</h2>
          </div>

          <div class="info-grid">
            <div class="info-item"><strong>Turma / Etapa</strong><span>${activeTurmaName}</span></div>
            <div class="info-item"><strong>Data do Encontro</strong><span>${new Date(data).toLocaleDateString()}</span></div>
            <div class="info-item"><strong>Tema Central</strong><span>${tema}</span></div>
            <div class="info-item"><strong>Cor Litúrgica</strong><span>${cor}</span></div>
            <div class="info-item"><strong>Horário</strong><span>${activeTurmaObj?.horario || 'Regular'}</span></div>
            <div class="info-item"><strong>Catequista</strong><span>${activeTurmaObj?.comunidade_id === 'c1' ? 'Coordenação' : 'Catequista Responsável'}</span></div>
          </div>

          <h3 class="section-title">Roteiro e Desenvolvimento</h3>
          <div class="content-box">
            ${obs ? obs : '<em>Nenhum roteiro detalhado registrado para este encontro.</em>'}
          </div>

          <h3 class="section-title">Recursos e Materiais</h3>
          <div style="border: 1px dashed #ccc; padding: 15px; border-radius: 4px; min-height: 80px;">
             <!-- Espaço para check list manual -->
             <ul style="list-style-type: square; padding-left: 20px; color: #666; margin: 0;">
                <li>Bíblia Sagrada</li>
                <li>_________________________________________</li>
                <li>_________________________________________</li>
             </ul>
          </div>

          <div class="footer">Gerado pelo sistema Lumen Fidei - Documento Pastoral de Uso Interno</div>
          <script>window.print();</script>
        </body>
      </html>
    `;

    win.document.write(html);
    win.document.close();
  };

  const handlePrintChamada = () => {
    if (!currentEncontroDetails) return;

    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    const html = `
      <html>
        <head><title>Lista de Presença - ${new Date(currentEncontroDetails.data).toLocaleDateString()}</title>${printStyles}</head>
        <body>
          <div class="header">
            <h1>${paroquia.nome}</h1>
            <h2>Registro de Frequência</h2>
          </div>

          <div class="info-grid">
             <div class="info-item"><strong>Turma</strong><span>${activeTurmaName}</span></div>
             <div class="info-item"><strong>Encontro</strong><span>${currentEncontroDetails.tema}</span></div>
             <div class="info-item"><strong>Data</strong><span>${new Date(currentEncontroDetails.data).toLocaleDateString()}</span></div>
             <div class="info-item"><strong>Total de Alunos</strong><span>${activeCatequizandos.length}</span></div>
          </div>

          <table>
            <thead>
              <tr>
                <th style="width: 5%">#</th>
                <th style="width: 50%">Catequizando</th>
                <th style="width: 15%">Status</th>
                <th style="width: 30%">Assinatura / Observação</th>
              </tr>
            </thead>
            <tbody>
              ${activeCatequizandos.map((aluno, index) => {
                const status = getStatus(aluno.id);
                const statusText = status === 'P' ? 'Presente' : status === 'F' ? 'Falta' : 'Justificada';
                return `
                  <tr>
                    <td>${index + 1}</td>
                    <td>${aluno.nome_completo}</td>
                    <td>${status ? statusText : '___________'}</td>
                    <td></td>
                  </tr>
                `;
              }).join('')}
            </tbody>
          </table>

          <div style="margin-top: 60px; display: flex; justify-content: space-between; font-size: 12px; padding: 0 40px;">
             <div style="text-align: center; border-top: 1px solid #000; width: 40%; padding-top: 5px;">Assinatura do Catequista</div>
             <div style="text-align: center; border-top: 1px solid #000; width: 40%; padding-top: 5px;">Visto da Coordenação</div>
          </div>

          <div class="footer">Gerado pelo sistema Lumen Fidei - ${new Date().toLocaleDateString()}</div>
          <script>window.print();</script>
        </body>
      </html>
    `;

    win.document.write(html);
    win.document.close();
  };

  // --- END PRINT FUNCTIONS ---

  const handleConsultAi = async () => {
    if (!newEncontro.data) return;
    setIsLoadingAi(true);
    setAiSuggestion(null);
    setCustomPrompt(''); // Reset prompt on new search

    const suggestion = await getLiturgicalSuggestions(newEncontro.data, activeTurmaName);

    if (suggestion) {
        setAiSuggestion(suggestion);
        // Auto-map color approximate
        let mapColor = LiturgicalColor.GREEN;
        const sColor = suggestion.cor.toLowerCase();
        if (sColor.includes('roxo') || sColor.includes('lilás')) mapColor = LiturgicalColor.PURPLE;
        else if (sColor.includes('vermelho')) mapColor = LiturgicalColor.RED;
        else if (sColor.includes('branco') || sColor.includes('dourado') || sColor.includes('amarelo')) mapColor = LiturgicalColor.WHITE;

        setNewEncontro(prev => ({
            ...prev,
            cor_liturgica: mapColor,
            // Don't auto-fill theme yet, let user choose to apply
        }));
    }
    setIsLoadingAi(false);
  };

  const handleGenerateScript = async () => {
      if (!newEncontro.data) return;
      setIsGeneratingScript(true);

      const script = await generateMeetingScript(
          newEncontro.data, 
          activeTurmaName, 
          aiSuggestion, 
          customPrompt
      );

      setNewEncontro(prev => ({
          ...prev,
          tema: prev.tema || aiSuggestion?.tema_sugerido || "Encontro Catequético",
          observacoes: script
      }));

      setIsGeneratingScript(false);
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
    setAiSuggestion(null);
    setCustomPrompt('');
  };

  const handleUpdateDetails = () => {
    if (currentEncontroDetails) {
        updateEncontro({
            ...currentEncontroDetails,
            tema: editingValues.tema || currentEncontroDetails.tema,
            data: editingValues.data || currentEncontroDetails.data,
            cor_liturgica: editingValues.cor_liturgica || currentEncontroDetails.cor_liturgica,
            observacoes: editingValues.observacoes || ''
        });
        setIsEditing(false);
    }
  };

  const toggleConcluido = () => {
      if (currentEncontroDetails) {
          updateEncontro({
              ...currentEncontroDetails,
              concluido: !currentEncontroDetails.concluido
          });
      }
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-900">Encontros & Frequência</h2>
        <select 
          value={selectedTurma}
          onChange={(e) => {
            setSelectedTurma(e.target.value);
            setSelectedEncontro(null);
            setIsChamadaMode(false);
          }}
          className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-church-500 focus:border-church-500 block p-2.5"
        >
          {turmas.map(turma => (
            <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-4 bg-gray-50 border-b border-gray-200">
            <h3 className="font-semibold text-gray-700">Agenda da Turma</h3>
          </div>
          <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false);
                    setIsEditing(false);
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-colors flex justify-between items-center ${selectedEncontro === encontro.id ? 'bg-church-50 border-l-4 border-church-500' : ''}`}
              >
                <div>
                  <p className="font-medium text-gray-900">{encontro.tema}</p>
                  <div className="flex items-center text-xs text-gray-500 mt-1 space-x-2">
                    <span className="flex items-center"><Calendar size={12} className="mr-1"/> {new Date(encontro.data).toLocaleDateString()}</span>
                    {encontro.concluido && <span className="flex items-center text-green-600"><CheckCircle size={12} className="mr-1"/> Realizado</span>}
                  </div>
                </div>
                <ChevronRight size={16} className="text-gray-400" />
              </button>
            ))}
            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full p-3 text-center text-sm text-church-600 font-medium hover:bg-church-50 transition-colors flex items-center justify-center"
            >
              <Plus size={16} className="mr-1"/> Agendar Novo Encontro
            </button>
          </div>
        </div>

        {/* Details / Attendance Area */}
        <div className="lg:col-span-2 space-y-6">
          {selectedEncontro && currentEncontroDetails ? (
            <div className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${isChamadaMode ? 'ring-2 ring-church-500 shadow-lg' : ''}`}>
               {/* HEADER DO ENCONTRO */}
               <div className={`p-6 border-b border-gray-200 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 ${isChamadaMode ? 'bg-church-50' : ''}`}>
                  <div className="flex-1 w-full">
                    {isEditing ? (
                        <div className="space-y-3 w-full bg-gray-50 p-3 rounded-lg border border-gray-200">
                            <div>
                                <label className="text-xs text-gray-500 font-bold uppercase">Tema</label>
                                <input 
                                    type="text"
                                    value={editingValues.tema} 
                                    onChange={e => setEditingValues({...editingValues, tema: e.target.value})}
                                    className="w-full font-bold text-gray-900 border-b border-gray-300 bg-transparent focus:border-church-500 outline-none text-lg"
                                />
                            </div>
                            <div className="flex gap-4">
                                <div>
                                    <label className="text-xs text-gray-500 font-bold uppercase">Data</label>
                                    <input 
                                        type="date"
                                        value={editingValues.data} 
                                        onChange={e => setEditingValues({...editingValues, data: e.target.value})}
                                        className="block text-sm bg-transparent border-b border-gray-300 focus:border-church-500 outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="text-xs text-gray-500 font-bold uppercase">Cor Litúrgica</label>
                                    <select 
                                        value={editingValues.cor_liturgica} 
                                        onChange={e => setEditingValues({...editingValues, cor_liturgica: e.target.value as LiturgicalColor})}
                                        className="block text-sm bg-transparent border-b border-gray-300 focus:border-church-500 outline-none"
                                    >
                                        {Object.values(LiturgicalColor).map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="flex items-center gap-2">
                                <h3 className="text-xl font-bold text-gray-900">{currentEncontroDetails.tema}</h3>
                                {currentEncontroDetails.concluido && (
                                    <span className="px-2 py-0.5 rounded-full bg-green-100 text-green-800 text-xs font-bold flex items-center">
                                        <Check size={12} className="mr-1"/> Realizado
                                    </span>
                                )}
                            </div>
                            <p className="text-sm text-gray-500 flex items-center mt-1">
                            <Clock size={16} className="mr-1"/> 
                            {new Date(currentEncontroDetails.data).toLocaleDateString()} • {currentEncontroDetails.cor_liturgica}
                            </p>
                        </>
                    )}
                  </div>

                  <div className="flex space-x-2 shrink-0">
                     {!isChamadaMode ? (
                        <>
                            {!isEditing && (
                                <button 
                                    onClick={handlePrintPauta}
                                    className="px-3 py-2 text-sm bg-gray-100 text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-200 flex items-center transition-colors"
                                    title="Imprimir Plano Completo do Encontro"
                                >
                                    <Printer size={16} />
                                </button>
                            )}

                            {isEditing ? (
                                <div className="flex space-x-2">
                                    <button 
                                        onClick={() => { setIsEditing(false); setEditingValues({}); }}
                                        className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg border border-transparent hover:border-red-100"
                                    >
                                        Cancelar
                                    </button>
                                    <button 
                                        onClick={handleUpdateDetails}
                                        className="px-4 py-2 text-sm bg-church-600 text-white rounded-lg hover:bg-church-700 flex items-center shadow-sm"
                                    >
                                        <Save size={16} className="mr-2"/> Salvar
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={() => {
                                        setEditingValues({
                                            tema: currentEncontroDetails.tema,
                                            data: currentEncontroDetails.data,
                                            cor_liturgica: currentEncontroDetails.cor_liturgica,
                                            observacoes: currentEncontroDetails.observacoes
                                        });
                                        setIsEditing(true);
                                    }}
                                    className="px-3 py-2 text-sm bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center transition-colors"
                                >
                                    <Edit3 size={16} className="mr-2"/> Editar
                                </button>
                            )}

                            {!isEditing && (
                                <button 
                                    onClick={() => setIsChamadaMode(true)}
                                    className="px-4 py-2 text-sm bg-church-600 text-white rounded-lg hover:bg-church-700 flex items-center font-semibold shadow-sm"
                                >
                                    <Users size={16} className="mr-2"/> Chamada
                                </button>
                            )}
                        </>
                     ) : (
                        <>
                            <button 
                                onClick={handlePrintChamada}
                                className="px-3 py-2 text-sm bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center font-semibold"
                                title="Imprimir Lista de Chamada"
                            >
                                <Printer size={16} className="mr-2"/> Imprimir Lista
                            </button>
                            <button 
                                onClick={() => setIsChamadaMode(false)}
                                className="px-4 py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center font-semibold"
                            >
                                <Check size={16} className="mr-2"/> Salvar Chamada
                            </button>
                        </>
                     )}
                  </div>
               </div>

               <div className="p-6">
                 {isChamadaMode ? (
                     // ROLL CALL MODE INTERFACE
                     <div className="space-y-4">
                         <div className="bg-yellow-50 p-3 rounded-lg flex items-start text-sm text-yellow-800 border border-yellow-100 mb-4">
                            <AlertCircle size={16} className="mt-0.5 mr-2 shrink-0"/>
                            <p>Toque no nome do catequizando para alternar entre <strong>Presente</strong> e <strong>Falta</strong>.</p>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {activeCatequizandos.map(aluno => {
                                 const status = getStatus(aluno.id);
                                 const isPresent = status === 'P';
                                 const isAbsent = status === 'F';

                                 return (
                                     <button 
                                        key={aluno.id}
                                        onClick={() => togglePresenca(aluno.id)}
                                        className={`p-4 rounded-xl border-2 flex items-center justify-between transition-all duration-200 
                                            ${isPresent ? 'border-green-500 bg-green-50' : ''}
                                            ${isAbsent ? 'border-red-300 bg-red-50 opacity-70' : ''}
                                            ${!status ? 'border-gray-200 bg-white hover:border-church-300' : ''}
                                        `}
                                     >
                                         <div className="flex items-center">
                                             <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm mr-3 transition-colors
                                                 ${isPresent ? 'bg-green-200 text-green-800' : 'bg-gray-100 text-gray-500'}
                                             `}>
                                                 {aluno.nome_completo.charAt(0)}
                                             </div>
                                             <div className="text-left">
                                                 <p className={`font-bold ${isPresent ? 'text-green-900' : 'text-gray-900'}`}>{aluno.nome_completo}</p>
                                                 <p className="text-xs text-gray-500">{isPresent ? 'Presente' : isAbsent ? 'Ausente' : 'Toque para marcar'}</p>
                                             </div>
                                         </div>
                                         <div>
                                             {isPresent && <CheckCircle className="text-green-600" size={24} />}
                                         </div>
                                     </button>
                                 )
                             })}
                         </div>
                     </div>
                 ) : (
                     // VIEW MODE & OBSERVATIONS
                     <div className="space-y-6">
                        {/* Attendance Summary */}
                        <div className="bg-gray-50 rounded-lg p-4 border border-gray-100">
                             <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">Frequência</h4>
                             {activeCatequizandos.length > 0 ? (
                                <div className="flex flex-wrap gap-2">
                                    {activeCatequizandos.map(aluno => {
                                        const status = getStatus(aluno.id);
                                        return (
                                            <div key={aluno.id} className={`text-xs px-2 py-1 rounded border flex items-center
                                                ${status === 'P' ? 'bg-green-100 border-green-200 text-green-700' : ''}
                                                ${status === 'F' ? 'bg-red-100 border-red-200 text-red-700' : ''}
                                                ${!status ? 'bg-white border-gray-200 text-gray-500' : ''}
                                            `}>
                                                <div className={`w-2 h-2 rounded-full mr-2 ${status === 'P' ? 'bg-green-500' : status === 'F' ? 'bg-red-500' : 'bg-gray-300'}`}></div>
                                                {aluno.nome_completo.split(' ')[0]}
                                            </div>
                                        )
                                    })}
                                </div>
                             ) : <p className="text-sm text-gray-500">Sem alunos.</p>}
                        </div>

                        {/* Observations / Log */}
                        <div>
                             <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Roteiro / Plano do Encontro</h4>

                             {isEditing ? (
                                 <div className="space-y-2">
                                     <textarea 
                                        className="w-full border border-gray-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-church-500 outline-none min-h-[200px]"
                                        value={editingValues.observacoes}
                                        onChange={(e) => setEditingValues({...editingValues, observacoes: e.target.value})}
