                                 <div className="bg-white border border-gray-200 rounded-lg p-6 text-sm text-gray-800 whitespace-pre-wrap leading-relaxed shadow-sm">
                                     {currentEncontroDetails.observacoes || <span className="text-gray-400 italic">Nenhum roteiro registrado. Clique em Editar para adicionar.</span>}
                                 </div>
