              <div className="flex items-center space-x-2 mb-2">
                <span className="bg-white/20 px-2 py-1 rounded text-xs font-semibold uppercase tracking-wide">Liturgia</span>
              </div>
              <h3 className="text-2xl font-bold mb-1">Ano Litúrgico</h3>
              <p className="text-green-100 text-sm max-w-lg">
