      {/* Modal Novo Encontro */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
             <div className="bg-church-600 p-4 flex justify-between items-center text-white shrink-0">
                <h3 className="font-bold">Agendar Novo Encontro</h3>
                <button onClick={() => { setIsModalOpen(false); setAiSuggestion(null); setCustomPrompt(''); }}><X size={20} /></button>
             </div>

             <form onSubmit={handleSaveEncontro} className="p-6 space-y-4 overflow-y-auto">
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Data do Encontro</label>
                   <div className="flex gap-2">
                       <input 
                          type="date" 
                          required
                          value={newEncontro.data}
                          onChange={e => setNewEncontro({...newEncontro, data: e.target.value})}
                          className="flex-1 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                       />
                       <button
                          type="button"
                          onClick={handleConsultAi}
                          disabled={!newEncontro.data || isLoadingAi}
                          className="bg-purple-100 text-purple-700 px-3 py-2 rounded-lg font-semibold text-sm hover:bg-purple-200 transition-colors flex items-center disabled:opacity-50"
                          title="Consultar Santo, Cor e Ideias para a data"
                       >
                           {isLoadingAi ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} className="mr-2"/>}
                           IA Pastoral
                       </button>
                   </div>
                   <p className="text-xs text-gray-500 mt-1">Selecione a data e clique na IA para sugestões.</p>
                </div>

                {/* Liturgical Info Card (AI) with Custom Prompt */}
                {aiSuggestion && (
                    <div className="p-4 rounded-lg border bg-gradient-to-br from-indigo-50 to-white border-indigo-200 animate-fade-in relative group">
                        <div className="flex justify-between items-start mb-2">
                            <h4 className="font-bold text-gray-900 text-sm flex items-center">
                                <Sparkles size={14} className="text-indigo-500 mr-2"/>
                                Liturgia do Dia
                            </h4>
                        </div>

                        <div className="grid grid-cols-2 gap-2 text-xs mb-3">
                           <div><span className="font-bold text-gray-700">Santo:</span> {aiSuggestion.santo}</div>
                           <div><span className="font-bold text-gray-700">Cor:</span> {aiSuggestion.cor}</div>
                        </div>

                        {/* Custom Context Input Area */}
                        <div className="mt-3 pt-3 border-t border-indigo-100">
                             <label className="block text-xs font-bold text-indigo-700 mb-1">
                                O que você quer abordar neste encontro?
                             </label>
                             <textarea 
                                value={customPrompt}
                                onChange={(e) => setCustomPrompt(e.target.value)}
                                placeholder="Ex: Focar na importância da obediência aos pais; Preparar para a festa junina..."
                                className="w-full text-sm border border-indigo-200 rounded p-2 focus:ring-2 focus:ring-indigo-500 outline-none bg-white/80 h-16 resize-none mb-2"
                             />
                             <button 
                                type="button"
                                onClick={handleGenerateScript}
                                disabled={isGeneratingScript}
                                className="w-full bg-indigo-600 text-white py-2 rounded text-sm font-semibold hover:bg-indigo-700 flex items-center justify-center transition-colors shadow-sm"
                             >
                                 {isGeneratingScript ? <Loader2 size={16} className="animate-spin mr-2" /> : <Wand2 size={16} className="mr-2" />}
                                 {customPrompt ? 'Gerar Roteiro Personalizado' : 'Gerar Roteiro Sugerido'}
                             </button>
                        </div>
                    </div>
                )}

                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Tema do Encontro</label>
                   <input 
                      type="text" 
                      required
                      value={newEncontro.tema}
                      onChange={e => setNewEncontro({...newEncontro, tema: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                      placeholder="Ex: Os Mandamentos"
                   />
                </div>

                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Cor Litúrgica</label>
                   <select 
                      value={newEncontro.cor_liturgica}
                      onChange={e => setNewEncontro({...newEncontro, cor_liturgica: e.target.value as LiturgicalColor})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none"
                   >
                      {Object.values(LiturgicalColor).map(cor => (
                         <option key={cor} value={cor}>{cor}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Roteiro / Observações</label>
                   <textarea 
                      value={newEncontro.observacoes}
                      onChange={e => setNewEncontro({...newEncontro, observacoes: e.target.value})}
                      className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-church-500 outline-none h-24"
                      placeholder="O roteiro gerado pela IA aparecerá aqui..."
                   />
                </div>
                <button 
                  type="submit"
                  className="w-full bg-church-600 text-white py-2 rounded-lg font-semibold hover:bg-church-700 transition-colors"
