  nome_responsavel: string; // Mantido para compatibilidade rápida, pega o 1º responsável
  telefone_responsavel: string; // Mantido para compatibilidade rápida
  sacramentos: {
    batismo: boolean;
    eucaristia: boolean;
    crisma: boolean;
  };
  observacoes_pastorais: string;
  familia_id?: string;
}

export interface Responsavel {
  id: string;
  nome: string;
  parentesco: string; // Pai, Mãe, Padrinho, Avó, Tio...
  telefone: string;
  casado_igreja: boolean;
  sacramentos: {
    batismo: boolean;
    eucaristia: boolean;
    crisma: boolean;
  };
  observacoes: string;
}

export interface Familia {
  id: string;
  sobrenome: string; // Ex: Família Silva
  responsaveis: Responsavel[]; // Lista dinâmica de responsáveis
  endereco: string;
  telefone_principal: string;
  observacoes: string;
}

export interface Catequista {
  id: string;
  nome: string;
  email: string;
  telefone: string;
  comunidade_id: string;
  tempo_servico_anos: number;
}

export enum LiturgicalColor {
