interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const { catequizandos, familias, catequistas, turmas, addCatequizando, addFamilia, addCatequista, paroquia } = useData();

  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filters state
  const [filterEtapa, setFilterEtapa] = useState('');
  const [filterAno, setFilterAno] = useState('');

  // --- FORM STATES ---

  // 1. Student Form
  const [studentForm, setStudentForm] = useState({
     nome_completo: '',
     data_nascimento: '',
     telefone: '', 
     turma_id: '',
     batismo: false,
     eucaristia: false,
     crisma: false,
     observacoes_pastorais: '',
     familia_id: '',
     nome_responsavel: '',
     telefone_responsavel: ''
  });

  // 2. Family/Address Form
  const [familyForm, setFamilyForm] = useState({
     sobrenome: '',
     endereco: '',
     telefone_principal: '',
     observacoes: ''
  });

  // 3. Dynamic Responsibles List
  const [responsaveisList, setResponsaveisList] = useState<Omit<Responsavel, 'id'>[]>([]);

  // 4. Temporary Responsible Input (for adding to list)
  const [tempResponsavel, setTempResponsavel] = useState({
      nome: '',
      parentesco: 'Mãe',
      telefone: '',
      casado_igreja: false,
      sacramentos: { batismo: false, eucaristia: false, crisma: false },
      observacoes: ''
  });

  // 5. Catechist Form
  const [newCatequista, setNewCatequista] = useState({
    nome: '',
    email: '',
    telefone: '',
    data_nascimento: '',
    tempo_servico_anos: 0,
    comunidade_id: 'c1',
    turma_id: '',
    experiencia_anterior: '',
    observacoes: ''
  });

  // Extract unique filter options from Turmas
  const uniqueEtapas = Array.from(new Set(turmas.map(t => t.etapa_nome).filter(Boolean))) as string[];
  const uniqueAnos = Array.from(new Set(turmas.map(t => t.ano))).sort((a: number, b: number) => b - a);

  const filteredCatequizandos = catequizandos.filter(c => {
    const matchesSearch = c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase());
    const turma = turmas.find(t => t.id === c.turma_id);
    const matchesEtapa = filterEtapa ? turma?.etapa_nome === filterEtapa : true;
    const matchesAno = filterAno ? turma?.ano.toString() === filterAno : true;
    return matchesSearch && matchesEtapa && matchesAno;
  });

  const filteredCatequistas = catequistas.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = familias.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    if (!phone) return;
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  const calculateAge = (dateString: string) => {
    if (!dateString) return '-';
    const today = new Date();
    const birthDate = new Date(dateString);
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        age--;
    }
    return age;
  };

  // --- PRINT LOGIC ---
  const handlePrintList = () => {
    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    const printStyles = `
      <style>
        body { font-family: 'Inter', sans-serif; padding: 20px; color: #1a1a1a; font-size: 12px; }
        .header { text-align: center; margin-bottom: 20px; border-bottom: 2px solid #e5e7eb; padding-bottom: 15px; }
        .header h1 { font-size: 16px; font-weight: bold; margin: 0; text-transform: uppercase; }
        .header h2 { font-size: 12px; font-weight: normal; margin: 5px 0 0; color: #666; }
        table { width: 100%; border-collapse: collapse; margin-top: 10px; }
        th, td { border: 1px solid #e5e7eb; padding: 6px 8px; text-align: left; vertical-align: top; }
