import React, { useState } from 'react';
import { Search, Plus, User, Droplets, MessageCircle, HeartHandshake, MapPin, X, Trash2, Smartphone, Printer, Briefcase, Calendar, Mail, BookOpen, Church } from 'lucide-react';
import { useData } from '../contexts/DataContext';
import { Responsavel, Catequista, Catequizando, Familia } from '../types';
import { MOCK_COMUNIDADES } from '../constants';

interface PeopleManagerProps {
  initialTab?: 'catequizandos' | 'familias' | 'catequistas';
}

const PeopleManager: React.FC<PeopleManagerProps> = ({ initialTab = 'catequizandos' }) => {
  const { catequizandos, familias, catequistas, turmas, addCatequizando, addFamilia, addCatequista, paroquia } = useData();

  const [activeTab, setActiveTab] = useState<'catequizandos' | 'familias' | 'catequistas'>(initialTab);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Filters state
  const [filterEtapa, setFilterEtapa] = useState('');
  const [filterAno, setFilterAno] = useState('');

  // --- FORM STATES ---

  // 1. Student Form
  const [studentForm, setStudentForm] = useState({
     nome_completo: '',
     data_nascimento: '',
     telefone: '', 
     turma_id: '',
     batismo: false,
     eucaristia: false,
     crisma: false,
     observacoes_pastorais: '',
     familia_id: '',
     nome_responsavel: '',
     telefone_responsavel: ''
  });

  // 2. Family/Address Form
  const [familyForm, setFamilyForm] = useState({
     sobrenome: '',
     endereco: '',
     telefone_principal: '',
     observacoes: ''
  });

  // 3. Dynamic Responsibles List
  const [responsaveisList, setResponsaveisList] = useState<Omit<Responsavel, 'id'>[]>([]);

  // 4. Temporary Responsible Input (for adding to list)
  const [tempResponsavel, setTempResponsavel] = useState({
      nome: '',
      parentesco: 'Mãe',
      telefone: '',
      casado_igreja: false,
      sacramentos: { batismo: false, eucaristia: false, crisma: false },
      observacoes: ''
  });

  // 5. Catechist Form
  const [newCatequista, setNewCatequista] = useState({
    nome: '',
    email: '',
    telefone: '',
    data_nascimento: '',
    tempo_servico_anos: 0,
    comunidade_id: '',
    turma_id: '',
    experiencia_anterior: '',
    observacoes: ''
  });

  // Extract unique filter options from Turmas
  const uniqueEtapas = Array.from(new Set(turmas.map(t => t.etapa_nome).filter(Boolean))) as string[];
  const uniqueAnos = Array.from(new Set(turmas.map(t => t.ano))).sort((a: number, b: number) => b - a);

  const filteredCatequizandos = catequizandos.filter(c => {
    const matchesSearch = c.nome_completo.toLowerCase().includes(searchTerm.toLowerCase());
    const turma = turmas.find(t => t.id === c.turma_id);
    const matchesEtapa = filterEtapa ? turma?.etapa_nome === filterEtapa : true;
    const matchesAno = filterAno ? turma?.ano.toString() === filterAno : true;
    return matchesSearch && matchesEtapa && matchesAno;
  });

  const filteredCatequistas = catequistas.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredFamilias = familias.filter(f => 
    f.sobrenome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openWhatsApp = (phone: string) => {
    if (!phone) return;
    const cleanPhone = phone.replace(/\D/g, '');
    const url = `https://wa.me/55${cleanPhone}`;
    window.open(url, '_blank');
  };

  const calculateAge = (dateString: string) => {
    if (!dateString) return '-';
    const today = new Date();
    const birthDate = new Date(dateString);
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        age--;
    }
    return age;
  };

  // --- PRINT LOGIC ---
  const handlePrintList = () => {
    const win = window.open('', '', 'width=800,height=600');
    if (!win) return;

    const printStyles = `
      <style>
        body { font-family: 'Inter', sans-serif; padding: 20px; color: #1a1a1a; font-size: 12px; }
        .header { text-align: center; margin-bottom: 20px; border-bottom: 2px solid #e5e7eb; padding-bottom: 15px; }
        .header h1 { font-size: 16px; font-weight: bold; margin: 0; text-transform: uppercase; }
        .header h2 { font-size: 12px; font-weight: normal; margin: 5px 0 0; color: #666; }
        table { width: 100%; border-collapse: collapse; margin-top: 10px; }
        th, td { border: 1px solid #e5e7eb; padding: 6px 8px; text-align: left; vertical-align: top; }
        th { background-color: #f9fafb; font-weight: 600; text-transform: uppercase; font-size: 10px; }
        .footer { margin-top: 30px; text-align: center; font-size: 9px; color: #9ca3af; border-top: 1px solid #e5e7eb; padding-top: 10px; }
        @media print { button { display: none; } body { padding: 0; } }
      </style>
    `;

    let tableContent = '';
    const title = activeTab === 'catequizandos' 
        ? 'Relatório Geral de Catequizandos' 
        : activeTab === 'catequistas' 
            ? 'Ficha da Equipe de Catequese' 
            : 'Registro de Famílias';

    if (activeTab === 'catequizandos') {
        tableContent = `
          <thead>
            <tr>
              <th>Nome Completo</th>
              <th>Idade</th>
              <th>Turma</th>
              <th>Sacramentos Recebidos</th>
              <th>Responsáveis</th>
            </tr>
          </thead>
          <tbody>
            ${filteredCatequizandos.map(student => {
               const turma = turmas.find(t => t.id === student.turma_id);
               const age = calculateAge(student.data_nascimento);
               const familia = familias.find(f => f.id === student.familia_id);
               const sacraments = [];
               if (student.sacramentos.batismo) sacraments.push('Batismo');
               if (student.sacramentos.eucaristia) sacraments.push('Eucaristia');
               if (student.sacramentos.crisma) sacraments.push('Crisma');

               const respNames = familia?.responsaveis 
                 ? familia.responsaveis.map(r => `${r.nome} (${r.parentesco}) - ${r.telefone}`).join('<br>')
                 : `${student.nome_responsavel} (${student.telefone_responsavel})`;

               return `
                 <tr>
                   <td>${student.nome_completo}</td>
                   <td>${age} anos</td>
                   <td>${turma?.etapa_nome || '-'}</td>
                   <td>${sacraments.join(', ') || 'Nenhum'}</td>
                   <td>${respNames}</td>
                 </tr>
               `;
            }).join('')}
          </tbody>
        `;
    } else if (activeTab === 'catequistas') {
        tableContent = `
          <thead>
            <tr>
              <th>Nome</th>
              <th>Telefone / E-mail</th>
              <th>Tempo de Serviço</th>
              <th>Turma Atual</th>
            </tr>
          </thead>
          <tbody>
            ${filteredCatequistas.map(cat => {
                const turma = turmas.find(t => t.id === cat.turma_id);
                return `
                 <tr>
                   <td>${cat.nome}</td>
                   <td>${cat.telefone}<br>${cat.email}</td>
                   <td>${cat.tempo_servico_anos} anos</td>
                   <td>${turma?.etapa_nome || 'Sem turma'}</td>
                 </tr>
               `;
            }).join('')}
          </tbody>
        `;
    } else {
        tableContent = `
          <thead>
            <tr>
              <th>Sobrenome</th>
              <th>Endereço</th>
              <th>Telefone</th>
              <th>Responsáveis</th>
            </tr>
          </thead>
          <tbody>
            ${filteredFamilias.map(fam => {
                const respNames = fam.responsaveis.map(r => r.nome).join(', ');
                return `
                 <tr>
                   <td>${fam.sobrenome}</td>
                   <td>${fam.endereco}</td>
                   <td>${fam.telefone_principal}</td>
                   <td>${respNames}</td>
                 </tr>
               `;
            }).join('')}
          </tbody>
        `;
    }

    const html = `
      <html>
        <head><title>${title}</title>${printStyles}</head>
        <body>
          <div class="header">
            <h1>${paroquia.nome}</h1>
            <h2>${title}</h2>
          </div>
          <table>${tableContent}</table>
          <div class="footer">Gerado pelo sistema Lumen Fidei - ${new Date().toLocaleDateString()}</div>
          <script>window.print();</script>
        </body>
      </html>
    `;

    win.document.write(html);
    win.document.close();
  };

  const handleSaveCatequizando = (e: React.FormEvent) => {
    e.preventDefault();
    addCatequizando({
