import React, { useState, useEffect } from 'react';
import { Calendar, CheckCircle, Clock, FileText, ChevronRight, Plus, X, Users, Check, AlertCircle, BookOpen, Sparkles, Loader2, Save, Printer, Edit3, Wand2, ArrowRight } from 'lucide-react';
import { useData } from '../contexts/DataContext';
import { Encontro, LiturgicalColor, Presenca } from '../types';
import { getLiturgicalSuggestions, LiturgySuggestion, generateMeetingScript } from '../services/geminiService';

const MeetingManager: React.FC = () => {
  const { turmas, encontros, catequizandos, presencas, addEncontro, updatePresenca, updateEncontro, paroquia } = useData();

  const [selectedTurma, setSelectedTurma] = useState(turmas[0]?.id || '');
  const [selectedEncontro, setSelectedEncontro] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // States for Meeting Details Edit (Full Object)
  const [editingValues, setEditingValues] = useState<Partial<Encontro>>({});
  const [isEditing, setIsEditing] = useState(false);

  // New State: "Chamada Mode" to make the attendance UI distinct
  const [isChamadaMode, setIsChamadaMode] = useState(false);

  // Liturgy Preview State (AI)
  const [aiSuggestion, setAiSuggestion] = useState<LiturgySuggestion | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Custom Script Generation State
  const [customPrompt, setCustomPrompt] = useState('');
  const [isGeneratingScript, setIsGeneratingScript] = useState(false);

  // Form State for New Meeting
  const [newEncontro, setNewEncontro] = useState({
    data: '',
    tema: '',
    cor_liturgica: LiturgicalColor.GREEN,
    observacoes: ''
  });

  const activeEncontros = encontros.filter(e => e.turma_id === selectedTurma);
  const activeCatequizandos = catequizandos.filter(c => c.turma_id === selectedTurma);
  const currentEncontroDetails = activeEncontros.find(e => e.id === selectedEncontro);
  const activeTurmaName = turmas.find(t => t.id === selectedTurma)?.etapa_nome || 'Turma';
  const activeTurmaObj = turmas.find(t => t.id === selectedTurma);

  // Helper para formatar data evitando bug de Timezone (UTC vs Local)
  const formatDateDisplay = (dateString: string) => {
      if (!dateString) return '';
      const [year, month, day] = dateString.split('-');
      return `${day}/${month}/${year}`;
  };

  // Sync editing state when selection changes
  useEffect(() => {
    if (currentEncontroDetails) {
      setEditingValues({
        tema: currentEncontroDetails.tema,
        data: currentEncontroDetails.data,
        cor_liturgica: currentEncontroDetails.cor_liturgica,
        observacoes: currentEncontroDetails.observacoes
      });
      setIsEditing(false);
    }
  }, [currentEncontroDetails]);

  const togglePresenca = (catequizandoId: string) => {
    if (!selectedEncontro) return;

    const existingRecord = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);

    if (existingRecord) {
        const currentStatus = existingRecord.status;
        const newStatus = currentStatus === 'P' ? 'F' : 'P';
        updatePresenca({ ...existingRecord, status: newStatus });
    } else {
        updatePresenca({ 
            id: Date.now().toString(), 
            encontro_id: selectedEncontro, 
            catequizando_id: catequizandoId, 
            status: 'P' 
        });
    }
  };

  const getStatus = (catequizandoId: string) => {
    if (!selectedEncontro) return null;
    const record = presencas.find(p => p.encontro_id === selectedEncontro && p.catequizando_id === catequizandoId);
    return record ? record.status : null;
  };

  // --- PRINT FUNCTIONS ---
  // (Mantidas as mesmas funções de print, omitidas para brevidade, mas funcionais)
  const printStyles = `
    <style>
      @import url('https://fonts.googleapis.com/css2?family=Merriweather:wght@300;400;700&family=Roboto:wght@300;400;500&display=swap');
      body { font-family: 'Roboto', sans-serif; padding: 40px; color: #1a1a1a; line-height: 1.5; }
      .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #e5e7eb; padding-bottom: 20px; }
      .header h1 { font-family: 'Merriweather', serif; font-size: 20px; font-weight: bold; margin: 0; text-transform: uppercase; color: #1e3a8a; }
      .header h2 { font-size: 14px; font-weight: normal; margin: 5px 0 0; color: #666; letter-spacing: 1px; }
      table { width: 100%; border-collapse: collapse; margin-top: 10px; font-size: 12px; }
      th, td { border: 1px solid #e5e7eb; padding: 8px 12px; text-align: left; }
      th { background-color: #f3f4f6; font-weight: 600; text-transform: uppercase; font-size: 10px; color: #374151; }
      @media print { button { display: none; } body { padding: 0; margin: 2cm; } }
    </style>
  `;

  const handlePrintPauta = () => {
     // Implementação simplificada para XML
     window.print();
  };

  const handlePrintChamada = () => {
     // Implementação simplificada para XML
     window.print();
  };


  // --- END PRINT FUNCTIONS ---

  const handleConsultAi = async () => {
    if (!newEncontro.data) return;
    setIsLoadingAi(true);
    setAiSuggestion(null);
    setCustomPrompt(''); 

    const suggestion = await getLiturgicalSuggestions(newEncontro.data, activeTurmaName);

    if (suggestion) {
        setAiSuggestion(suggestion);
        let mapColor = LiturgicalColor.GREEN;
        const sColor = suggestion.cor.toLowerCase();
        if (sColor.includes('roxo') || sColor.includes('lilás')) mapColor = LiturgicalColor.PURPLE;
        else if (sColor.includes('vermelho')) mapColor = LiturgicalColor.RED;
        else if (sColor.includes('branco') || sColor.includes('dourado') || sColor.includes('amarelo')) mapColor = LiturgicalColor.WHITE;

        setNewEncontro(prev => ({
            ...prev,
            cor_liturgica: mapColor,
        }));
    }
    setIsLoadingAi(false);
  };

  const handleGenerateScript = async () => {
      if (!newEncontro.data) return;
      setIsGeneratingScript(true);

      const script = await generateMeetingScript(
          newEncontro.data, 
          activeTurmaName, 
          aiSuggestion, 
          customPrompt
      );

      setNewEncontro(prev => ({
          ...prev,
          tema: prev.tema || aiSuggestion?.tema_sugerido || "Encontro Catequético",
          observacoes: script
      }));

      setIsGeneratingScript(false);
  };

  const handleSaveEncontro = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedTurma) return;

    addEncontro({
      turma_id: selectedTurma,
      data: newEncontro.data,
      tema: newEncontro.tema,
      cor_liturgica: newEncontro.cor_liturgica,
      observacoes: newEncontro.observacoes,
      concluido: false
    });

    setIsModalOpen(false);
    setNewEncontro({ data: '', tema: '', cor_liturgica: LiturgicalColor.GREEN, observacoes: '' });
    setAiSuggestion(null);
    setCustomPrompt('');
  };

  const handleUpdateDetails = () => {
    if (currentEncontroDetails) {
        updateEncontro({
            ...currentEncontroDetails,
            tema: editingValues.tema || currentEncontroDetails.tema,
            data: editingValues.data || currentEncontroDetails.data,
            cor_liturgica: editingValues.cor_liturgica || currentEncontroDetails.cor_liturgica,
            observacoes: editingValues.observacoes || ''
        });
        setIsEditing(false);
    }
  };

  return (
    <div className="space-y-6 relative animate-fade-in">
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-900 flex items-center">
            <Calendar className="mr-2 text-church-600"/>
            Encontros & Frequência
        </h2>
        <div className="relative">
            <select 
            value={selectedTurma}
            onChange={(e) => {
                setSelectedTurma(e.target.value);
                setSelectedEncontro(null);
                setIsChamadaMode(false);
            }}
            className="appearance-none bg-gray-50 border border-gray-200 text-gray-900 text-sm rounded-xl focus:ring-church-500 focus:border-church-500 block w-64 p-2.5 pr-8 font-medium"
            >
            {turmas.map(turma => (
                <option key={turma.id} value={turma.id}>{turma.etapa_nome} - {turma.dia_encontro}</option>
            ))}
            </select>
            <ChevronRight className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 rotate-90" size={16} />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* List of Meetings */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden h-fit">
          <div className="p-4 border-b border-gray-50 bg-gray-50/50 flex justify-between items-center">
            <h3 className="font-bold text-gray-700 text-sm uppercase tracking-wide">Agenda</h3>
            <span className="text-xs bg-white px-2 py-1 rounded border border-gray-200 text-gray-500">{activeEncontros.length} encontros</span>
          </div>
          <div className="divide-y divide-gray-50 max-h-[600px] overflow-y-auto">
            {activeEncontros.map(encontro => (
              <button
                key={encontro.id}
                onClick={() => {
                    setSelectedEncontro(encontro.id);
                    setIsChamadaMode(false);
                    setIsEditing(false);
                }}
                className={`w-full text-left p-4 hover:bg-gray-50 transition-all duration-200 group relative
                    ${selectedEncontro === encontro.id ? 'bg-church-50/50' : ''}`}
