                {selectedEncontro === encontro.id && (
                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-church-500 rounded-r"></div>
                )}
                <div className="flex justify-between items-center">
                    <div>
                        <div className="flex items-center space-x-2 mb-1">
                            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">{formatDateDisplay(encontro.data)}</span>
                            {encontro.concluido && <CheckCircle size={12} className="text-emerald-500" />}
                        </div>
                        <p className={`font-semibold text-sm ${selectedEncontro === encontro.id ? 'text-church-700' : 'text-gray-700'}`}>{encontro.tema}</p>
                    </div>
                    <ChevronRight size={16} className={`text-gray-300 transition-transform ${selectedEncontro === encontro.id ? 'text-church-500 translate-x-1' : 'group-hover:translate-x-1'}`} />
                </div>
              </button>
            ))}

            <div className="p-4">
                <button 
                onClick={() => setIsModalOpen(true)}
