             </div>

             <form onSubmit={handleSaveEncontro} className="p-6 space-y-6 overflow-y-auto">
                <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Data do Encontro</label>
                   <div className="flex gap-3">
                       <input 
