                       </button>
                   </div>
                </div>

                {/* AI Suggestion Card */}
                {aiSuggestion && (
                    <div className="p-5 rounded-xl border bg-gradient-to-br from-indigo-50/50 to-white border-indigo-100 relative animate-fade-in">
                        <h4 className="font-bold text-indigo-900 text-sm flex items-center mb-3">
                            <Sparkles size={14} className="text-indigo-500 mr-2"/>
                            Liturgia Sugerida
                        </h4>

                        <div className="text-xs space-y-1 mb-4 text-gray-600">
                           <p><strong className="text-gray-900">Santo:</strong> {aiSuggestion.santo}</p>
                           <p><strong className="text-gray-900">Cor:</strong> {aiSuggestion.cor}</p>
                        </div>

                        <div className="border-t border-indigo-100 pt-3">
                             <label className="block text-xs font-bold text-indigo-800 mb-2">
                                Contexto Específico (Opcional)
                             </label>
                             <div className="flex gap-2">
                                <input 
                                    value={customPrompt}
                                    onChange={(e) => setCustomPrompt(e.target.value)}
                                    placeholder="Ex: Focar na obediência..."
                                    className="flex-1 text-sm border border-indigo-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                                />
                                <button 
                                    type="button"
                                    onClick={handleGenerateScript}
                                    disabled={isGeneratingScript}
                                    className="bg-indigo-600 text-white px-3 py-2 rounded-lg hover:bg-indigo-700 transition-colors"
                                >
                                    {isGeneratingScript ? <Loader2 size={18} className="animate-spin" /> : <Wand2 size={18} />}
                                </button>
                             </div>
                        </div>
                    </div>
                )}

                <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Tema</label>
                   <input 
                      type="text" 
                      required
                      value={newEncontro.tema}
                      onChange={e => setNewEncontro({...newEncontro, tema: e.target.value})}
                      className="w-full border border-gray-200 bg-gray-50 rounded-xl p-3 focus:ring-2 focus:ring-church-500 focus:bg-white outline-none transition-all"
                      placeholder="Ex: Iniciação à Vida Cristã"
                   />
                </div>

                <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Cor Litúrgica</label>
                   <select 
                      value={newEncontro.cor_liturgica}
                      onChange={e => setNewEncontro({...newEncontro, cor_liturgica: e.target.value as LiturgicalColor})}
                      className="w-full border border-gray-200 bg-gray-50 rounded-xl p-3 focus:ring-2 focus:ring-church-500 focus:bg-white outline-none transition-all"
                   >
                      {Object.values(LiturgicalColor).map(cor => (
                         <option key={cor} value={cor}>{cor}</option>
                      ))}
                   </select>
                </div>

                <button 
                  type="submit"
                  className="w-full bg-church-600 text-white py-3.5 rounded-xl font-bold hover:bg-church-700 transition-all shadow-lg shadow-church-200 transform active:scale-95 mt-4"
                >
                   Confirmar Agendamento
                </button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MeetingManager;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCatecheticalPlan = async (
  etapa: string,
  tempo: string,
  userPrompt: string
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview', // Atualizado para modelo mais rápido
      contents: `Atue como um catequista católico experiente e fiel ao magistério.
      Crie um plano de encontro detalhado com a seguinte estrutura:
      1. Tema e Objetivo
      2. Acolhida e Oração Inicial
      3. Leitura Bíblica (indicar passagem apropriada)
      4. Desenvolvimento do Tema (Dinâmica ou Explicação)
      5. Atividade Prática
      6. Oração Final

      Contexto do Encontro:
      - Etapa Catequética: ${etapa}
      - Tempo Litúrgico: ${tempo}
      - Solicitação Específica: ${userPrompt}

      Utilize uma linguagem acolhedora e adequada à faixa etária da etapa informada.`,
      config: {
        systemInstruction: "Você é um assistente pastoral especializado em catequese católica.",
      },
    });

    return response.text || "Não foi possível gerar o plano neste momento.";
  } catch (error) {
    console.error("Erro ao gerar plano:", error);
    return "Ocorreu um erro ao comunicar com o assistente IA. Por favor, verifique a chave de API.";
  }
};

export interface LiturgySuggestion {
  santo: string;
  vida_breve: string; // Novo campo
  cor: string;
  leituras: string;
  tema_sugerido: string;
  ideia_dinamica: string;
}

export const getLiturgicalSuggestions = async (date: string, etapaContext: string): Promise<LiturgySuggestion | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview', // Modelo mais rápido e eficiente para JSON
      contents: `Para a data ${date} e uma turma de catequese da etapa '${etapaContext}', forneça sugestões litúrgicas e pastorais.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            santo: { 
              type: Type.STRING,
              description: "O Santo do dia ou Solenidade litúrgica católica."
            },
            vida_breve: {
              type: Type.STRING,
              description: "Uma frase curta e inspiradora sobre quem foi este santo ou o significado da solenidade (máx 20 palavras)."
            },
            cor: { 
              type: Type.STRING,
              description: "A cor litúrgica (Verde, Branco, Vermelho, Roxo ou Rosa)."
            },
            leituras: { 
              type: Type.STRING,
              description: "As referências bíblicas da liturgia diária (1ª Leitura, Salmo, Evangelho)."
            },
            tema_sugerido: { 
              type: Type.STRING,
              description: "Um tema curto para o encontro baseado na liturgia ou no santo."
            },
            ideia_dinamica: { 
              type: Type.STRING,
              description: "Uma sugestão muito breve (1 frase) de atividade prática."
            }
          },
          required: ["santo", "vida_breve", "cor", "leituras", "tema_sugerido", "ideia_dinamica"]
        }
      },
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as LiturgySuggestion;
  } catch (error) {
    console.error("Erro ao buscar sugestão litúrgica:", error);
    return null;
  }
};

export const generateMeetingScript = async (
  date: string, 
  etapa: string, 
  liturgyInfo: LiturgySuggestion | null, 
  userCustomRequest: string
): Promise<string> => {
  try {
    const liturgyContext = liturgyInfo 
      ? `Liturgia do dia: ${liturgyInfo.santo} (${liturgyInfo.vida_breve}). Leituras: ${liturgyInfo.leituras}.` 
      : `Data: ${date}.`;

    const prompt = `
      Crie um Roteiro de Encontro de Catequese detalhado e pronto para uso.

      Informações:
      - Data: ${date}
      - Turma/Etapa: ${etapa}
      - ${liturgyContext}
      - PEDIDO ESPECIAL DO CATEQUISTA: "${userCustomRequest}"

      O roteiro deve conectar a liturgia do dia com o pedido do catequista.
      Estrutura do Roteiro (Use Markdown):
      1. 🎯 Objetivo do Encontro
      2. 🙏 Oração Inicial (Sugira uma oração específica)
      3. 📖 Aprofundamento (Como explicar o tema para esta idade)
      4. 🎨 Dinâmica/Atividade (Passo a passo breve)
      5. ✨ Encerramento
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "Você é um coordenador de catequese sábio e prático. Suas respostas são estruturadas para serem lidas e aplicadas diretamente na sala.",
      },
    });

    return response.text || "";
  } catch (error) {
    console.error("Erro ao gerar roteiro:", error);
    return "Erro ao gerar roteiro. Tente novamente.";
  }
};

