            <NavItem view={ViewState.FAMILIAS} icon={HeartHandshake} label="Famílias" />

            {isCoordenador && (
              <>
                <NavItem view={ViewState.CATEQUISTAS} icon={BookOpen} label="Equipe de Catequese" />
                <NavItem view={ViewState.ESTRUTURA} icon={Church} label="Estrutura Paroquial" />
              </>
            )}
          </div>
        </nav>

        {/* Sidebar Footer */}
        <div className="p-4 bg-gradient-to-t from-[#F9FAFB] to-transparent">
          <button 
            onClick={logout}
            className="w-full flex items-center justify-center space-x-2 text-sm font-medium text-gray-500 hover:text-red-600 hover:bg-red-50 p-3 rounded-xl transition-all duration-200 group"
          >
            <LogOut size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span>Sair do Sistema</span>
          </button>
          <p className="text-center text-[10px] text-gray-300 mt-2">Versão 2.1 • Catholic Dev</p>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative">
        <div className="max-w-7xl mx-auto p-4 md:p-8 lg:p-12 pb-24">
          {children}
        </div>
      </main>
    </div>
  );
};

