import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import MeetingManager from './components/MeetingManager';
import PeopleManager from './components/PeopleManager';
import AiPlanner from './components/AiPlanner';
import ResourceLibrary from './components/ResourceLibrary';
import AttendanceReport from './components/AttendanceReport';
import Login from './components/Login';
import { ViewState } from './types';
import { Church } from 'lucide-react';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { DataProvider } from './contexts/DataContext';

// Main App Component with Auth Logic
const AuthenticatedApp: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { user } = useAuth();

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.ENCONTROS:
        return <MeetingManager />;
      case ViewState.RELATORIOS:
        return <AttendanceReport />;
      case ViewState.CATEQUIZANDOS:
        return <PeopleManager initialTab="catequizandos" />;
      case ViewState.MARKETING:
        return <PeopleManager initialTab="marketing" />;
      case ViewState.CATEQUISTAS:
        return <PeopleManager initialTab="catequistas" />;
      case ViewState.IA_ASSISTANT:
        return <AiPlanner />;
      case ViewState.MATERIAIS:
        return <ResourceLibrary />;
      case ViewState.ESTRUTURA:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 p-12 bg-white rounded-xl border border-dashed border-gray-300">
            <Church size={64} className="mb-4 text-gray-200" />
            <h3 className="text-xl font-medium text-gray-600">Estrutura Paroquial</h3>
            <p className="mt-2 text-center max-w-md">Gerenciamento de Diocese, Paróquia e Comunidades (Estrutura Hierárquica) estaria aqui no sistema completo.</p>
          </div>
        );
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

// Root Component deciding between Login and App
const Root: React.FC = () => {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? <AuthenticatedApp /> : <Login />;
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <DataProvider>
        <Root />
      </DataProvider>
    </AuthProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { Search, Plus, User, Droplets, MessageCircle, HeartHandshake, MapPin, X, Trash2, Smartphone, Printer, Briefcase, Calendar, Mail, BookOpen, Church, ChevronDown, Send } from 'lucide-react';
